def shorten_list_for_train_test(lis, seed=42, kind='train', which=''):

    # 1. Create a local, isolated random generator instance
    local_random = random.Random(seed)

    if which != '':
        kind = which

    lis = list(set(lis))

    # 2. Use the local instance for shuffling only
    local_random.shuffle(lis)

    # The rest of the logic remains the same
    train_inds = lis[:int(len(lis)*(2/3))]
    test_inds = lis[int(len(lis)*(2/3)):]

    if kind == 'train':
        return train_inds
    else:
        return test_inds
def FORMAT_ANSWER(val):
    """
    Formats a value (Fraction, int, float, or fraction-like string) into a
    consistent inline LaTeX string: \( value \) or \( \frac{num}{den} \).
    """

    # --- Handling Fraction Objects (Passed as objects) ---
    if isinstance(val, Fraction):
        if val.denominator == 1:
            # Whole number result (e.g., 15) -> \( 15 \)
            return "\\( {} \\)".format(val.numerator)
        else:
            # True fraction result (e.g., 10/15) -> \( \frac{10}{15} \)
            return "\\( \\frac{{{}}}{{{}}} \\)".format(val.numerator, val.denominator)

    # --- Handling Fraction Strings (Passed as strings like "2/3") ---
    # This logic assumes the 'val' is now a string like "2/3" or "10/15"
    if isinstance(val, str) and '/' in val:
        try:
            # Attempt to convert to a Fraction object to check for simplification (e.g., "4/2" -> 2)
            temp_frac = Fraction(val)
            if temp_frac.denominator == 1:
                 # Whole number result (e.g., 2 from "4/2")
                 return "\\( {} \\)".format(temp_frac.numerator)
            else:
                 # True fraction result (e.g., 2/3)
                 return "\\( \\frac{{{}}}{{{}}} \\)".format(temp_frac.numerator, temp_frac.denominator)
        except ValueError:
            # If the string isn't a valid fraction (e.g., "a/b"), fall through
            pass

    # --- Handling all other types (int, float, generic string, etc.) ---
    # This covers whole numbers (15, 9) and any unparsed generic value.
    return "\\( {} \\)".format(val)
