def is_fraction_or_not_whole(number):
    """
    Returns True if number is a fraction or not a whole number.
    Returns False if number is a whole integer.
    Accepts int, float, Fraction.
    """
    if isinstance(number, int):
        return False  # whole number (integer)
    elif isinstance(number, Fraction):
        # Check if fraction denominator is 1
        return number.denominator != 1
    elif isinstance(number, float):
        # Using is_integer() for floats
        return not number.is_integer()
    else:
        raise TypeError(f"Unsupported type {type(number)}")


def augment_firstterm_misconception(sample_size=70,which='train'):
    variants = []

    contexts = [
        "dots",
        "marbles",
        "triangles",
        "squares",
        "pentagons"
    ]

    pattern_params = [
        (Fraction(1,2),Fraction(1,4)),
        (Fraction(1,3),Fraction(1,6)),
        (Fraction(1,2), Fraction(1,2)),
        (5,2),
        (Fraction(1,3), Fraction(1,3)),

        (7,5),
        (Fraction(3,2), Fraction(3,2)),
        (Fraction(2,3),Fraction(4,5))



    ]
    for _ in range(sample_size):
        int1=random.randint(1,6)
        int2=random.randint(1,6)
        int3=random.randint(1,8)
        int4=random.randint(1,10)
        if random.random()<0.3 and int1!=int2:
            if random.random()<0.2 and int3!=int4:
              part1=Fraction(int1,int3)
              part2=Fraction(int2,int4)
            else:
              part1=Fraction(int1, int2)
              part2=Fraction(int1,int2)

        else:
            part1=int1
            part2=int2
        add_tup=(part1,part2)
        pattern_params.append(add_tup)


    pattern_indices = [6,7,8,9]

    for context in contexts:
        for first_term, diff in pattern_params:
            for n in pattern_indices:
                kind=random.choice(['correct','incorrect','incorrect','incorrect'])
                variant = make_firstterm_variant(context, first_term, diff, n,scenario=kind, which=which)
                variants.append(variant)

    return variants

