def augment_inversion_misconception(sample_size=140,which='train'):
    variants = []
    fraction_scenarios = [
        ("2/3", 15),
        ("3/4", 6),
        ("1/2", 8),
        ("3/5", 15),
        ("1/2",14),
        ('4/3',9),
        ('5/6',10),
        ('7/6',14)
    ]
    factors=[2,3,5]
    for _ in range(sample_size-6):
        factor=random.choice(factors)
        starting_point=random.randint(2,5)
        den=starting_point*factor
        whole=factor*random.randint(starting_point,starting_point+random.randint(1,5))
        scenario=(f"1/{den}",whole)
        if which!='train':
            if whole!=den:
                fraction_scenarios.append(scenario)
        else:
            fraction_scenarios.append(scenario)
    for frac_str, whole_number in fraction_scenarios:

            variants.append(make_inversion(frac_str, whole_number, scenario='incorrect',which=which))
            if random.random()<0.5:
                variants.append(make_inversion(frac_str, whole_number, scenario='correct',which=which))
                variants.append(make_inversion(frac_str, whole_number, scenario='correct_incomplete',which=which))
                variants.append(make_inversion(frac_str, whole_number, scenario='incorrect_incomplete',which=which))
    return variants

from fractions import Fraction
import math

def format_mixed_number_duplication(frac_obj):
    """
    Converts a Fraction object into a LaTeX-formatted string for a mixed number.
    Returns the original fraction string if it's not an improper fraction.
    Example: 5/3 -> 1 2/3
             6/2 -> 3
             1/2 -> 1/2
    """
    if frac_obj.denominator == 0:
        return ""  # Avoid division by zero, though unlikely with Fraction objects

    # If the fraction is less than 1, return the fraction itself
    if abs(frac_obj.numerator) < frac_obj.denominator:
        return rf"\frac{{{frac_obj.numerator}}}{{{frac_obj.denominator}}}"

    # If the fraction is an integer (e.g., 6/2)
    if frac_obj.numerator % frac_obj.denominator == 0:
        return str(frac_obj.numerator // frac_obj.denominator)

    # Calculate the whole number and the remaining fraction
    whole = frac_obj.numerator // frac_obj.denominator
    remainder = frac_obj.numerator % frac_obj.denominator

    # Handle negative fractions
    if frac_obj.numerator < 0:
        # For negative numbers, we need to adjust the logic to ensure the fractional part is positive
        # Example: -5/3 -> -2 + 1/3, but typically represented as -1 2/3
        # The Fraction object simplifies this for us: the sign is usually on the whole number.
        if whole < 0 and remainder != 0:
            # We use the absolute value for the fractional part
            return rf"{whole} \frac{{{abs(remainder)}}}{{{frac_obj.denominator}}}"

    # Standard positive mixed number
    return rf"{whole} \frac{{{remainder}}}{{{frac_obj.denominator}}}"
