def augment_mult_misconception(sample_size=120,which='train'):
    fraction_scenarios = [
        ("1/2", 6),
        ("1/5", 10),
        ("1/7", 14),
        ("1/9", 18),
        ("1/12",18)
    ]
    factors=[2,3,5]
    for _ in range(sample_size-6):
        factor=random.choice(factors)
        if random.random()<0.2:

          starting_point=random.randint(2,5)
          den=starting_point*factor
          whole=factor*random.randint(starting_point,starting_point+random.randint(1,5))
        else:
          den=random.randint(2,9)
          whole=factor*den

        scenario=(f"1/{den}",whole)
        fraction_scenarios.append(scenario)
    variants = []
    scenarios=['correct']*6+['incorrect']*18+['correct_incomplete']*6+['incorrect_incomplete']*6
    for frac_str, whole in fraction_scenarios:
        for scenario in scenarios:
            variant = make_mult_flip_change(frac_str, whole, scenario,which=which)
            if variant:
                variants.append(variant)
    return variants

def unsimplified_wrong_answer_swap_dividend(fraction, whole_number):
    fraction_num = int(fraction.split('/')[0])
    fraction_denom = int(fraction.split('/')[1])
    numerator = fraction_num * whole_number
    return numerator, fraction_denom  # returns numerator multiplied, denominator unchanged


