    incomplete_correct_explanations = swapdividend_explanations
    incomplete_swapdividend_explanations = swapdividend_explanations

    frac = Fraction(frac_str)
    reciprocal = Fraction(1, whole_number)
    denom = frac_str.split('/')[1]
