def goes_in_evenly(dividend,divisor):
    if dividend%divisor==0:
        return True
    return False
def augment_incomplete_misconception(sample_size=20):
    """Generate variants for 'Incomplete' misconception - correct reasoning but missing final step"""

    def fraction_simplification_variants():
        """Student identifies correct fraction but doesn't simplify"""
        variants = []

        # Only use fractions that can actually be simplified
        # Format: (shaded, total) - make sure shaded < total
        simplifiable_fractions = [
            (8, 12),   # 8/12 = 2/3
            (6, 9),    # 6/9 = 2/3
            (4, 8),    # 4/8 = 1/2
            (6, 12),   # 6/12 = 1/2
            (9, 15),   # 9/15 = 3/5
            (10, 16),  # 10/16 = 5/8
            (12, 18),  # 12/18 = 2/3
            (14, 21),  # 14/21 = 2/3
            (15, 20),  # 15/20 = 3/4
            (16, 24)   # 16/24 = 2/3
        ]

        shapes = ['rectangle', 'circle', 'triangle', 'square']
        parts_names = ['squares', 'sectors', 'triangles', 'parts']

        from fractions import Fraction

        for shaded, total in simplifiable_fractions:
            shape = random.choice(shapes)
            parts = random.choice(parts_names)

            question = (f"What fraction of the shape is shaded? Give your answer in its simplest form. "
                       f"[Image: A {shape} split into {total} equal {parts}. {shaded} of them are shaded.]")

            # Calculate the simplified fraction
            simplified = Fraction(shaded, total)

            # 1. TRUE_CORRECT: Fully simplified answer AND simplified in explanation
            explanation_correct = (f"I think it is {simplified.numerator}/{simplified.denominator} because there are {total} parts and {shaded} are shaded. "
                                  f"This simplifies to {simplified}.")
            variants.append({
                'QuestionText': question,
                'StudentExplanation': explanation_correct,
                'Category': ['True_Correct'],
                'Misconception': ['No Misconception'],
                'MC_Answer': FORMAT_ANSWER(f"{simplified.numerator}/{simplified.denominator}")
            })

            #CONCERN ABOUT THIS CODE
            # 2. TRUE_MISCONCEPTION (Incomplete): Simplified answer but doesn't explain simplification
            explanation_incomplete_right_answer = f"I think it is {simplified} because there are {total} parts and {shaded} are shaded."
            variants.append({
                'QuestionText': question,
                'StudentExplanation': explanation_incomplete_right_answer,
                'Category': ['True_Misconception'],
                'Misconception': ['Incomplete'],
                'MC_Answer': f"\\( \\frac{{{simplified.numerator}}}{{{simplified.denominator}}} \\)"
            })

            # 3. FALSE_MISCONCEPTION (Incomplete): Not simplified answer and not simplified in explanation
            explanation_incomplete = f"I think it is {shaded}/{total} because there are {total} parts and {shaded} are shaded."
            variants.append({
                'QuestionText': question,
                'StudentExplanation': explanation_incomplete,
                'Category': ['False_Misconception'],
                'Misconception': ['Incomplete'],
                'MC_Answer': f"\\( \\frac{{{shaded}}}{{{total}}} \\)"
            })

        return variants

