def augment_adding_across1(sample_size=12,which='train'):
    """Student adds numerators and denominators separately"""
    variants = []

    fractions_pairs = [
        ((1, 3), (2, 5)), ((1, 4), (3, 7)), ((2, 3), (1, 4)),
        ((3, 5), (1, 6)), ((1, 2), (2, 7)), ((4, 9), (1, 3))
    ]
    for _ in range(sample_size):
        num1=random.randint(1,12)
        num2=random.randint(1,12)
        den1=random.randint(1,12)
        den2=random.randint(1,12)
        
        sample_tup=((num1,den1),(num2,den2))
        if which!='train':
            if den1!=den2:
                fractions_pairs.append(sample_tup)
        else:
            fractions_pairs.append(sample_tup)

    for (num1, den1), (num2, den2) in fractions_pairs:
        question = f"\\( \\frac{{{num1}}}{{{den1}}}+\\frac{{{num2}}}{{{den2}}}= \\)"
        explanation = f"I added the top numbers: {num1} + {num2} = {num1 + num2}, and the bottom numbers: {den1} + {den2} = {den1 + den2}"

        variants.append({
            'QuestionText': question,
            'StudentExplanation': explanation,
            'Category': ['False_Misconception'],
            'Misconception': ['Adding_across'],
            'MC_Answer': FORMAT_ANSWER(f"{num1 + num2}/{den1 + den2}")
        })

    return variants

def make_subtraction(frac1, frac2, name1, name2, pronoun1, possessive1,
                     context, item, action, scenario='incorrect',which='train'):
    """Make a single subtraction misconception variant"""
    from fractions import Fraction

    fraction1_str = f"\\( \\frac{{{frac1.split('/')[0]}}}{{{frac1.split('/')[1]}}} \\)"
    fraction2_str = f"\\( \\frac{{{frac2.split('/')[0]}}}{{{frac2.split('/')[1]}}} \\)"

    reduce_language = ['Make sure to reduce your answer.', 'Simplify',
                       'Simplify if necessary', 'Write answer in simplest form']
    verb_map={'eaten':'eating',
             'shared':'sharing',
             'given':'giving'}
    past_tense_map={'eaten':'ate',
                   'shared':'shared',
                   'given':'gave'}
    past_tense_verb=past_tense_map[action]
    action_present=verb_map[action]
    question = context.format(
        name1=name1,
        name2=name2,
        pronoun1=pronoun1,
        possessive1=possessive1,
        frac1=fraction1_str,
        frac2=fraction2_str
    )
    question += f" What fraction of the whole {item} was {action}. {random.choice(reduce_language)}"

    f1 = Fraction(frac1)
    f2 = Fraction(frac2)
    subtraction_result = f1 - f2
    correct_answer = f1 * f2

    explanations_wrong = [
        f"Since something is being {action}, I subtract: {frac1} - {frac2}",
        f"I did {frac1} - {frac2}",
        f"I did {frac1} - {frac2} because the number is getting reduced",
        f"Since the number is being reduced you subtract",
        f"Because something is taken away, I subtract {frac2} from {frac1}",
        f"YOu since it is being {action} you need to take away",
        f"YOu since it is being {action} you need to take away {frac1}-{frac2}",
        f"since they are {action_present} the amount is reducing, therefore you must subtract",
        f"since they are {action_present} the amount is reducing, therefore you must subtract {frac1}-{frac2}",
        f"Do {frac1}-{frac2} to get the answer",
        f"since {pronoun1} is {action_present} the amount is getting smaller, so we can subtract",
        f"Because {pronoun1} is {action_present} the number is getting smaller, so we can subtract",
        f"Because {pronoun1} is {action_present} the number is getting smaller, so we can subtract {frac1}-{frac2}"

    ]
    explanations_wrong=shorten_list_for_train_test(explanations_wrong,kind=which)

    explanations_correct = [
        f"To find {frac2} of {frac1}, I multiply: {frac1} × {frac2}",
        f"I multiplied {frac1} by {frac2} to get the answer",
        f"Multiply the fractions: {frac1} × {frac2} = {correct_answer}",
        f"{pronoun1} is {action_present} the {item} and {pronoun1} {past_tense_verb} {frac1} of it, then {pronoun1} {frac2} of that amount,so you take {frac1} of {frac2} which means multiplying the fractions",
         f"The correct operation is multiplication because we are finding the intersection of two fractional parts, which is calculated as the product of {frac1} and {frac2}.",
        f"Since {name1} {past_tense_verb} a portion of {possessive1} {item}, we find {frac2} of the initial {frac1} by multiplying them. {frac1} times {frac2} equals {correct_answer}.",
        f"We need to find a fraction ({frac2}) of a part of the whole {item} ({frac1}), so we multiply the two fractions together: {frac1} × {frac2}.",
        f"The word 'of' between the two fractions means we must multiply {frac1} and {frac2} to find the final amount. The result is {correct_answer}."
    ]
    explanations_correct=shorten_list_for_train_test(explanations_correct,kind=which)
    if scenario == 'incorrect':
        explanation = random.choice(explanations_wrong)
        if subtraction_result != correct_answer and subtraction_result > 0:
            if random.random()<CHANGED_CAT_PROB:
                return {
                    'QuestionText': question,
                    'StudentExplanation': explanation,
                    'Category': ['True_Misconception'],
                    'Misconception': ['Subtraction'],
                    'MC_Answer': FORMAT_ANSWER(correct_answer)
                }
            return {
                'QuestionText': question,
                'StudentExplanation': explanation,
                'Category': ['False_Misconception'],
                'Misconception': ['Subtraction'],
                'MC_Answer': FORMAT_ANSWER(subtraction_result)
            }
        else:
            return {
                'QuestionText': question,
                'StudentExplanation': explanation,
                'Category': ['True_Misconception'],
                'Misconception': ['Subtraction'],
                'MC_Answer': FORMAT_ANSWER(subtraction_result)
            }

    elif scenario == 'correct':
        explanation = random.choice(explanations_correct)
        if random.random()<CHANGED_CAT_PROB:
            return {
            'QuestionText': question,
            'StudentExplanation': explanation,
            'Category': ['True_Correct'],
            'Misconception': ['No Misconception'],
            'MC_Answer': FORMAT_ANSWER(subtraction_result)
        }
        return {
            'QuestionText': question,
            'StudentExplanation': explanation,
            'Category': ['True_Correct'],
            'Misconception': ['No Misconception'],
            'MC_Answer': FORMAT_ANSWER(correct_answer)
        }

    elif scenario == 'incomplete':
        numerator1 = int(frac1.split('/')[0])
        denominator1 = int(frac1.split('/')[1])
        numerator2 = int(frac2.split('/')[0])
        denominator2 = int(frac2.split('/')[1])

        result_numerator = numerator1 * numerator2
        result_denominator = denominator1 * denominator2
        explanations_incomplete_correct = [
            f"To find {frac2} of {frac1}, I multiply: {frac1} × {frac2}",
            f"I multiplied {frac1} by {frac2} to get the answer",
            f"Multiply the fractions: {frac1} × {frac2} = {result_numerator}/{result_denominator}",
            f"{pronoun1} is {action_present} the {item} and {pronoun1} {past_tense_verb} {frac1} of it, then {pronoun1} {frac2} of that amount, so you take {frac1} of {frac2} which means multiplying the fractions",
             f"The correct operation is multiplication because we are finding the intersection of two fractional parts, which is calculated as the product of {frac1} and {frac2}.",
            f"Since {name1} {past_tense_verb} a portion of {possessive1} {item}, we find {frac2} of the initial {frac1} by multiplying them. {frac1} times {frac2} equals {result_numerator}/{result_denominator}.",
            f"We need to find a fraction ({frac2}) of a part of the whole {item} ({frac1}), so we multiply the two fractions together: {frac1} × {frac2}.",
            f"The word 'of' between the two fractions means we must multiply {frac1} and {frac2} to find the final amount. The result is {result_numerator}/{result_denominator}."
        ]
        explanation = random.choice(explanations_incomplete_correct)

        return {
            'QuestionText': question,
            'StudentExplanation': explanation,
            'Category': ['False_Misconception'],
            'Misconception': ['Incomplete'],
            'MC_Answer': f"\\( \\frac{{{result_numerator}}}{{{result_denominator}}} \\)"
        }

    elif scenario == 'incorrect_incomplete':
        unreduced_answer = subtract_fractions_nonreduced(frac1, frac2)
        unreduced_numerator = str(unreduced_answer).split('/')[0]
        unreduced_denominator = str(unreduced_answer).split('/')[1]
        enders = ['so', 'therefore', 'which equals']
        ender=random.choice(enders)
        ending=random.choice(enders)
        explanations_wrong_incomplete = [
        f"Since something is being {action}, I subtract: {frac1} - {frac2}",
        f"I did {frac1} - {frac2}",
        f"I did {frac1} - {frac2} because the number is getting reduced",
        f"Since the number is being reduced you subtract",
        f"Because something is taken away, I subtract {frac2} from {frac1}",
        f"YOu since it is being {action} you need to take away",
        f"YOu since it is being {action} you need to take away {frac1}-{frac2}",
        f"since they are {action_present} the amount is reducing, therefore you must subtract",
        f"since they are {action_present} the amount is reducing, therefore you must subtract {frac1}-{frac2} {ender} {unreduced_answer}",
        f"since they are {action_present} the amount is reducing, therefore you must subtract ",
        f"Do {frac1}-{frac2} to get the answer",
        f"Do {frac1}-{frac2} to get the answer ender {unreduced_answer}",
        f"since {pronoun1} is {action_present} the amount is getting smaller, so we can subtract",
        f"Because {pronoun1} is {action_present} the number is getting smaller, so we can subtract",
        f"Because {pronoun1} is {action_present} the number is getting smaller, so we can subtract {frac1}-{frac2}",
        f"Since something is being {action}, I subtract: {frac1} - {frac2} {random.choice(enders)} {unreduced_answer}"

    ]
        explanations_wrong_incomplete=shorten_list_for_train_test(explanations_wrong_incomplete,kind=which)
        explanation = random.choice(explanations_wrong_incomplete)

        return {
            'QuestionText': question,
            'StudentExplanation': explanation,
            'Category': ['False_Misconception'],
            'Misconception': ['Incomplete', 'Subtraction'],
            'MC_Answer': f"\\( \\frac{{{unreduced_numerator}}}{{{unreduced_denominator}}} \\)"
        }


def augment_subtraction(sample_size=40,which='train'):
    """Student uses subtraction when multiplication is needed + correct examples"""
    from fractions import Fraction

    original_names = [
        ('Sally', 'she', 'her'), ('Albert', 'he', 'his'), ('Emma', 'she', 'her'),
        ('John', 'he', 'his'), ('Esmeralda', 'she', 'her'), ('Luke', 'he', 'his'),
        ('Jerry', 'he', 'his'), ('Steven', 'he', 'his'), ('Maya', 'she', 'her'),
        ('Lucinda', 'she', 'her'), ('Jeremy', 'he', 'his'), ('Tom', 'he', 'his'),
        ('Jesus', 'he', 'his'), ('Lupita', 'she', 'her'),
        ('Alex', 'they', 'their'), ('Casey', 'they', 'their'), ('Taylor', 'they', 'their'),
    ]

    contexts = [
        ("{name1} has {frac1} of a cake. {name2} eats {frac2} of {name1}'s piece.", "cake", "eaten"),
        ("{name1} has {frac1} of pizza. {pronoun1} gives {frac2} of {possessive1} piece to {name2}.", "pizza", "given"),
        ("{name1} owns {frac1} of a chocolate bar. {pronoun1} shares {frac2} of {possessive1} portion.", "chocolate", "shared")
    ]

    fractions_incorrect = [("2/3", "1/3"), ("3/4", "1/2"), ("4/5", "2/5"), ("5/6", "1/3")]
    fractions_incomplete = [("2/4", "1/3"), ("3/5", "2/3"), ("4/5", "3/8"), ("5/6", "3/10")]
    fractions_both = [("4/6", "2/3"), ("4/5", "3/10"), ("5/6", "5/18")]

    scenarios = ['incorrect'] * 18 + ['correct']+['incomplete']+['incorrect_incomplete']

    variants = []

    for _ in range(sample_size):
        for scenario in scenarios:
            names = random.sample(original_names, 6)
            context, item, action = random.choice(contexts)

            frac1, frac2 = random.choice(fractions_incorrect)
            scenario = random.choice(scenarios)

            variant = make_subtraction(
                frac1, frac2,
                names[0][0], names[1][0], names[0][1], names[0][2],
                context, item, action,
                scenario=scenario,
                which=which
            )

            if variant:
                variants.append(variant)

    return variants
def subtract_fractions_nonreduced(frac1, frac2):
    num1, den1 = map(int, frac1.split("/"))
    num2, den2 = map(int, frac2.split("/"))
    lcm = den1 * den2  # Use product as common denominator to prevent reduction
    new_num1 = num1 * den2
    new_num2 = num2 * den1
    result_num = new_num1 - new_num2
    result_den = lcm
    return f"{result_num}/{result_den}"

def augment_inverse_operation(sample_size=5,which='train'):
    """Student uses wrong inverse operation + correct examples"""
    variants = []

    equations = [
        ("2y = 24", "y", 2, 24), ("3x = 36", "x", 3, 36),
        ("4n = 28", "n", 4, 28), ("5p = 45", "p", 5, 45)
    ]
    variables=['n','a','b','x','c','w','y','t']
    for _ in range(sample_size):
        coef=random.randint(2,10)
        right_side=random.randint(2,10)*coef
        var_name=random.choice(variables)
        equation=(f"{coef}{var_name}={right_side}",var_name,coef,right_side)
        equations.append(equation)
    for equation, variable, coefficient, result in equations:
        question = f"\\( {equation} \\) What is the value of \\( {variable} \\)?"

        # MISCONCEPTION VERSION - multiplies instead of divides
        explanation_wrong = f"To solve {equation}, I multiply both sides: {result} × {coefficient} = {result * coefficient}"
        variants.append({
            'QuestionText': question,
            'StudentExplanation': explanation_wrong,
            'Category': ['False_Misconception'],
            'Misconception': ['Inverse_operation'],
            'MC_Answer': f"\\( {result * coefficient} \\)"
        })

        # CORRECT VERSION - divides correctly
        correct_answer = result // coefficient
        explanation_correct = f"To solve {equation}, I divide both sides by {coefficient}: {result} ÷ {coefficient} = {correct_answer}"
        variants.append({
            'QuestionText': question,
            'StudentExplanation': explanation_correct,
            'Category': ['True_Correct'],
            'Misconception': ['No Misconception'],
            'MC_Answer': f"\\( {correct_answer} \\)"
        })

    return variants


def augment_multiplying_by_4(sample_size=20,which='train'):
    """Student multiplies when should divide (work rate problems) + correct examples"""
    variants = []

    scenarios = [
        ("build a wall", "people", "hours"),
        ("paint a house", "workers", "hours"),
        ("harvest a field", "farmers", "days")
    ]
    for _ in range(sample_size):
        for task, workers, time_unit in scenarios:
            original_workers = random.randint(2, 5)
            total_time = random.randint(100, 300)
            new_workers = original_workers * 4

            question = (f"It takes {original_workers} {workers} a total of {total_time} {time_unit} to {task}. "
                       f"How long would it take if {new_workers} {workers} {task.split()[1]} the same {task.split()[2]}?")

            # MISCONCEPTION VERSION - multiplies by 4
            explanation_wrong = (f"Since {original_workers} {workers} = {total_time} {time_unit}, "
                               f"I multiply by 4 to get {new_workers} {workers}: {total_time} × 4 = {total_time * 4}")
            variants.append({
                'QuestionText': question,
                'StudentExplanation': explanation_wrong,
                'Category': ['False_Misconception'],
                'Misconception': ['Multiplying_by_4'],
                'MC_Answer': FORMAT_ANSWER(total_time * 4)+f"{time_unit}"
            })

            # CORRECT VERSION - divides by 4
            correct_time = total_time // 4
            explanation_correct = (f"With 4 times more {workers}, it takes 1/4 the time: "
                                 f"{total_time} ÷ 4 = {correct_time}")
            variants.append({
                'QuestionText': question,
                'StudentExplanation': explanation_correct,
                'Category': ['True_Correct'],
                'Misconception': ['No Misconception'],
                'MC_Answer': FORMAT_ANSWER(correct_time)+ f"{time_unit}"
            })

    return variants

def unsimplified_correct_answer_multiplying(frac_str,whole):
    num=int(frac_str.split('/')[0])
    denom=int(frac_str.split('/')[1])
    new_num=whole*num
    return new_num,denom
def unsimplified_wrong_answer_inversion(frac_str,whole):
    num=int(frac_str.split('/')[0])
    denom=int(frac_str.split('/')[1])
    new_denom=whole*denom
    return num,new_denom
def make_base_rate(original_workers, new_workers, total_time,which='train'):
    """
    Creates a work-rate problem with base rate misconception and correct solution.
    original_workers: int, number of workers initially
    new_workers: int, new number of workers working on the same task
    total_time: int, time taken by original_workers

    Returns:
      A dict with question, explanation, answer, misconception, and category
    """
    tasks = ["build a wall",'make lemonade','build a fence','clean a pool','move supplies','lay brick','build a water fountain',
             'clean the house']
    workers_strs = ['workers',"people",'employees']
    time_units_list = ["hours",'minutes','seconds','days','weeks']
    task = random.choice(tasks)
    workers_str = random.choice(workers_strs)
    time_unit = random.choice(time_units_list)

    # Correct inverse proportionality calculation
    factor = new_workers / original_workers
    if int(factor)==factor:
      factor=int(factor)
    correct_answer = total_time / factor
    correct_time = correct_answer
    if correct_answer==int(correct_answer):

      if random.random() < 0.75:
          correct_time = int(correct_time)


    language1 = random.choice(['about','roughly'])
    language2 = random.choice(['would it take','is it going to take'])
    language3 = random.choice(["do",'Take'])

    questions = [
        (f"It takes {original_workers} {workers_str} a total of {total_time} {time_unit} to {task}. "
         f"How long would it take if {new_workers} {workers_str} did the same {task}?"),
        (f'If {original_workers} {workers_str} can {task} in {total_time} {time_unit} then how long {language2} {new_workers} {workers_str}'),
        (f"{original_workers}  {workers_str} take {language1} {total_time} {time_unit} to {task}, how long {language2} {new_workers} {workers_str}")
    ]
    question = random.choice(questions)

    # Pattern 1: Per-person time (total_time / original_workers)
    wrong_answer_per_person = total_time / original_workers
    if random.random() < 0.5:
        if random.random()<0.75:
          wrong_answer_per_person = int(wrong_answer_per_person)
    if wrong_answer_per_person==int(wrong_answer_per_person):
        if random.random()<0.75:
          wrong_answer_per_person=int(wrong_answer_per_person)

    explanations_per_person = [
        f"Because {total_time} divided by {original_workers} is {wrong_answer_per_person}",
        f"I did {total_time} divided by {original_workers} = {wrong_answer_per_person}",
        f"You {language3} {total_time} and divide by {original_workers} and you get {wrong_answer_per_person} {time_unit}",
        f"When you divide {original_workers} by {total_time}, you get {wrong_answer_per_person}",
        f"{total_time} divided by {original_workers} = {wrong_answer_per_person}",
        f"{original_workers} people = {total_time} {time_unit}, 1 person = {wrong_answer_per_person} {time_unit}",
        f"It takes {original_workers} people, {wrong_answer_per_person} {time_unit} a piece",
        f"Each person takes {wrong_answer_per_person} {time_unit}",
        f"If {original_workers} {workers_str} take {total_time} {time_unit}, then one person takes {wrong_answer_per_person} {time_unit}",
        f"Each of the {original_workers} {workers_str} works {wrong_answer_per_person} {time_unit}, so that's the answer",
        f"Since there are {original_workers} and it takes them {total_time}, so it would take {new_workers} {workers_str} {wrong_answer_per_person} {time_unit}",
        f"If you divide the number of {time_unit} and divide it by {original_workers} you get {wrong_answer_per_person} which is how many {time_unit} it takes for {new_workers} {workers_str}",
        f"{original_workers} {workers_str} to {task} takes {total_time} so it takes {new_workers} {workers_str} {wrong_answer_per_person} {time_unit}",
        f"And then I divided {total_time} by {original_workers}, I got this answer",
        f"I just divided {total_time} by {original_workers} to get {wrong_answer_per_person} {time_unit}",
        f"Because I did {total_time} divided by {original_workers} = {wrong_answer_per_person}",
        f"Because you divide by {original_workers} from {total_time}",
        f"You divide {original_workers} by {total_time} which equals {wrong_answer_per_person}",
        f"This is because {total_time} divided by {original_workers} is {wrong_answer_per_person}",
        f"I think this because I divided {total_time} by {original_workers} to get {wrong_answer_per_person}",
    ]
    explanations_per_person=shorten_list_for_train_test(explanations_per_person,kind=which)
    # Pattern 2: Multiply per-person time by new workers
    wrong_answer_multiply = (total_time / original_workers) * new_workers
    if wrong_answer_multiply==int(wrong_answer_multiply):
        if random.random() < 0.75:
          wrong_answer_multiply=int(wrong_answer_multiply)


    explanations_multiply = [
        f"{wrong_answer_per_person} times {new_workers} = 1 person {wrong_answer_per_person}",
        f"If you take the number of {time_unit} and multiply it by {original_workers}, you get the answer of {wrong_answer_multiply} which is what it takes to do {new_workers} {workers_str} in {time_unit}",
        f"One person takes {wrong_answer_per_person} {time_unit}, so {new_workers} {workers_str} take {wrong_answer_multiply} {time_unit}",
        f"Since 1 person does it in {wrong_answer_per_person} {time_unit}, multiply that by {new_workers} to get {wrong_answer_multiply} {time_unit}",
    ]
    explanations_multiply=shorten_list_for_train_test(explanations_multiply,kind=which)
    # Pattern 3: Keep total time constant
    wrong_answer_constant = total_time
    per_person_new = total_time / new_workers
    if per_person_new==int(per_person_new):
      if random.random() < 0.75:
          per_person_new = int(per_person_new)

    explanations_constant = [
        f"To build the wall takes {total_time} {time_unit} but every person works {per_person_new} {time_unit} instead of {wrong_answer_per_person}",
        f"to build the wall still takes {total_time} {time_unit} but every person works {per_person_new} {time_unit} instead of {wrong_answer_per_person}",
        f"The {task} still takes {total_time} {time_unit} no matter how many {workers_str}",
        f"It would still take {total_time} {time_unit} because the job size doesn't change",
    ]
    explanations_constant=shorten_list_for_train_test(explanations_constant,kind=which)
    language4 = random.choice(['factor','multiplier'])
    language5 = random.choice(['number','amount'])

    # Add to your make_base_rate function - replace the existing explanations_correct with this expanded version:



    explanations_correct = [
    # Original patterns
    (f"Since there are {factor} times more {workers_str}, it takes 1/{factor} the time: "
     f"{total_time} ÷ {factor} = {correct_time} {time_unit}"),
    (f"I divided {new_workers}/{original_workers} which gave a {language4} of {factor}, so you can divide the total time by this factor, "
     f"therefore {total_time}/{factor} which is {correct_time} {time_unit}"),
    (f"All I have to do is find out by what factor the number of {workers_str} increased by. "
     f"Since there were {original_workers} {workers_str}, the {language5} of {workers_str} increased by a factor of {factor}, "
     f"then I divide {total_time} by that {language5} giving me {correct_time} {time_unit}"),

    # Pattern: Mentions factor explicitly
    f"{new_workers} divided by {original_workers} is {factor} and then {total_time} divided by {factor} is {correct_time}",
    f"Since it is indirect proportion you would do {original_workers} x {factor} to get {new_workers} and then do {total_time}/{factor} since it is indirect proportion",
    f"{original_workers}x{factor}={new_workers}, {total_time}/{factor}={correct_time}, it will take {factor} times the amount of {workers_str} 1/{factor} of the amount of time",

    # Pattern: Multiply then divide (work-hours method)
    f"I think this because {original_workers} * {total_time} = {original_workers * total_time}. {original_workers * total_time}/{new_workers} = {correct_time}, suggesting that it would take {new_workers} {workers_str} {correct_time} {time_unit}",
    f"Because you times {total_time} by {original_workers} for 1 person = {original_workers * total_time} then do {original_workers * total_time} divided by {new_workers} because there are {new_workers} {workers_str}",

    # Pattern: Direct factor reasoning
    f"I think this because {new_workers} {workers_str} is {factor} times the amount of {original_workers} {workers_str} so the journey will be {factor} times quicker so you do {total_time} divided by {factor} to get {correct_time}",
    f"You do {original_workers}x{factor}={new_workers} so you do {total_time} divided by {factor}={correct_time}",
    f"Because if {original_workers} goes into {new_workers} {factor} times you would have to divide the time by {factor}",
    f"There are {factor} times the amount of {workers_str} working therefore it would take {factor} times less time to complete",
    f"{original_workers} goes into {new_workers} {factor} times, so divide {total_time} by {factor} = {correct_time} {time_unit}",

    # Pattern: Inverse proportion reasoning
    f"Because {original_workers} x {factor} is {new_workers} so {total_time} divided by {factor} is {correct_time}",
    f"Because to get from {original_workers} to {new_workers} you times by {factor} so you divide {total_time} by {factor}",
    f"I think this because {original_workers} times {factor} is {new_workers} so as this is inverse you have to do {total_time} divide by {factor} is {correct_time}",
    f"Because you times {original_workers} by {factor} and subsequently divide {total_time} by {factor}",
    f"Because you times the {workers_str} by {factor} so you divide the {time_unit} by {factor}",
    f"Because {original_workers} times {factor} = {new_workers} so we have to do the opposite to {total_time} because more {workers_str} means less time",
    f"I think this because {original_workers} multiply {factor} is {new_workers} so you do the opposite to the other side which is {total_time} divided by {factor} which is {correct_time} {time_unit}",
    f"Because x{factor} the {workers_str} divide by {factor} time",

    # Pattern: Inversely proportional (explicit)
    f"They are inversely proportional. {factor} times as many {workers_str}, so takes 1/{factor} of the time. {total_time}/{factor} = {correct_time} {time_unit}",
    f"The answer is {correct_time} {time_unit} because this is a ratio you do {total_time} divided by {factor} which is {correct_time}",

    # Pattern: Simple division statement
    f"Because you divide {total_time} by {factor} and get {correct_time}",
    f"The answer is {correct_time} {time_unit} because {total_time} divided by {factor} is {correct_time}",
    f"This is because {new_workers} divided by {original_workers} is {factor} and {total_time} divided by {factor} is {correct_time}",
    f"I did {new_workers} divided by {original_workers} equals {factor} then I divided {total_time} by {factor} which equals {correct_time}",

    # Pattern: Work-hours calculation variations
    f"{original_workers} {workers_str} = {total_time} {time_unit}, x{factor} {workers_str}, ÷ {factor} {time_unit}, {new_workers} {workers_str} = {correct_time} {time_unit}",
]
    explanations_correct=shorten_list_for_train_test(explanations_correct,kind=which)
    # Misconception version
    if random.random() < 0.75:
        # Generate misconception (75% of the time)
        # Now randomly choose which pattern to use with weighted probabilities
        # Based on your samples: ~80% per-person, ~10% multiply, ~10% constant
        rand = random.random()
        if rand < 0.80:  # 80% - per-person time
            explanation = random.choice(explanations_per_person)
            mc_answer = wrong_answer_per_person
        elif rand < 0.90:  # 10% - multiply
            explanation = random.choice(explanations_multiply)
            mc_answer = wrong_answer_multiply
        else:  # 10% - constant time
            explanation = random.choice(explanations_constant)
            mc_answer = wrong_answer_constant
        if random.random()<CHANGED_CAT_PROB:
          variant = {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["True_Misconception"],
            "Misconception": ["Base_rate"],
            "MC_Answer": f"\\( {correct_time} \\) {time_unit}"
        }
        else:
          variant = {
              "QuestionText": question,
              "StudentExplanation": explanation,
              "Category": ["False_Misconception"],
              "Misconception": ["Base_rate"],
              "MC_Answer": f"\\( {mc_answer} \\) {time_unit}"
          }
    else:
        # Generate correct answer (25% of the time)
        explanation = random.choice(explanations_correct)
        if random.random()<CHANGED_CAT_PROB:
            rand = random.random()
            if rand < 0.80:  # 80% - per-person time

              mc_answer = wrong_answer_per_person
            elif   rand < 0.90:  # 10% - multiply

                mc_answer = wrong_answer_multiply
            else:  # 10% - constant time

                mc_answer = wrong_answer_constant
            variant = {
              "QuestionText": question,
              "StudentExplanation": explanation,
              "Category": ["False_Correct"],
              "Misconception": ["No Misconception"],
              "MC_Answer": f"\\( {mc_answer} \\) {time_unit}"
          }
        else:

          variant = {
              "QuestionText": question,
              "StudentExplanation": explanation,
              "Category": ["True_Correct"],
              "Misconception": ["No Misconception"],
              "MC_Answer": f"\\( {correct_time} \\) {time_unit}"
          }

    return variant

def augment_base_rate(sample_size=75,which='train'):
    variants=[]
    parameters=[(3,9,150),
               (5,15,90),
               (2,8,120),
               (3,15,120),
               (3,6,120),
               (2,16,80)]
    for _ in range(sample_size-len(parameters)):
        int1=random.randint(2,12)
        int2=int1*random.randint(2,5)
        int3=find_lcm(int1,int2)*random.randint(2,7)
        new_param=(int1,int2,int3)
        parameters.append(new_param)
    parameters*=15
    for original_workers,new_workers,total_time in parameters:
        variants.append(make_base_rate(original_workers, new_workers, total_time,which=which))
    return variants
# Master function to generate all misconception types
def multiply_fractions_correctly(num1, den1, num2, den2):
    new_num = num1 * num2
    new_den = den1 * den2
    return new_num, new_den

def multiply_fraction_division_misc(num1, den1, num2, den2):
    # Division, as "multiply by reciprocal"
    new_num = int(num1 * den2)
    new_den = int(num2 * den1)
    return new_num, new_den, f"{num1}/{den1} divided by {num2}/{den2}", Fraction(new_num, new_den)


def multiply_fractions_correctly(num1, den1, num2, den2):
    new_num = num1 * num2
    new_den = den1 * den2
    return new_num, new_den

def multiply_fraction_division_misc(num1, den1, num2, den2):
    # Division, as "multiply by reciprocal"
    new_num = int(num1 * den2)
    new_den = int(num2 * den1)
    return new_num, new_den, f"{num1}/{den1} divided by {num2}/{den2}", Fraction(new_num, new_den)


def make_division(frac1, frac2, scenario='incorrect', force_non_context_specific=True,which='train'):
    names = ['Tim','John','Jessica','Jesus','Mookie','Chris','Max','Melissa','Maria','Lupita']
    contexts = ['cake','burger','pizza','pie']
    language1 = ['eats','consumes']
    questions = [
        '{name1} has {frac1} of a whole piece of {context}. {name2} {language1} {frac2} of this piece. What fraction of the whole {context} has {name2} {language2}?',
        'If {name1} eats {frac1} of a {context} then {name2} {language1} {frac2} of what {name1} has {language1}, what fraction of the original {context} was {language2}?',
    ]
    questions2 = [
        '{name1} has {frac1} of a wall left to paint. {name2} paints {frac2} of this area. What fraction of the whole wall did {name2} paint?',
        '{name1} owns {frac1} of a garden plot. {name2} waters {frac2} of that plot. What fraction of the full plot did {name2} water?',
        '{name1} has {frac1} of a book remaining to read. {name2} reads {frac2} of what is left. What fraction of the whole book did {name2} read?',
        '{name1} brings {frac1} of a large box of supplies. {name2} distributes {frac2} of these supplies. What fraction of the original box did {name2} distribute?',
        '{name1} has {frac1} of a roll of ribbon. {name2} uses {frac2} of the ribbon. What fraction of the whole roll did {name2} use?',
        '{name1} runs {frac1} of a marathon. {name2} completes {frac2} of that distance. What fraction of the entire marathon did {name2} run?',
        '{name1} sets aside {frac1} of a day for study. {name2} spends {frac2} of that time on mathematics. What fraction of the whole day did {name2} spend on mathematics?'
    ]

    questions_to_language_map = {
    questions2[0]: {'language3': 'paints', 'context': 'wall'},
    questions2[1]: {'language3': 'waters', 'context': 'garden plot'},
    questions2[2]: {'language3': 'reads', 'context': 'book'},
    questions2[3]: {'language3': 'distributes', 'context': 'supplies'},
    questions2[4]: {'language3': 'uses', 'context': 'ribbons'},
    questions2[5]: {'language3': 'runs', 'context': 'marathon'},
    questions2[6]: {'language3': 'spends', 'context': 'day'}
}

    past_tense_language = {'eats': 'eaten', 'consumes': 'consumed'}
    past_tense_language2={'eats':'eaten','consumes':'consumed'}
    result_language_options = ['which equals','which is','and I get', 'and that results in']

    explanations_correct = [
        "I took the original fraction {frac1} and multiplied by {frac2} to get {unsimp_num}/{unsimp_den} {result_language}  {result}",
        "After {name1} {language3} {frac1} of the {context} there is {frac1} that has been done, we take {frac2} of that which means we multiply the two fractions {frac1}x{frac2} which results in {unsimp_num}/{unsimp_den} {result_language} {result}",
        "Once {name1} {language3} {frac1} that becomes the fraction of the amount that has been done, which is basically 1 times {frac1}, so then you treat that result as if it is the new whole and multiply it by {frac2} and that is {unsimp_num}/{unsimp_den} {result_language} {result}",
        "{frac1} already {language3} by {name1} so then take {frac2} of that which means multiplying the fractions, so you do {frac1} multiplied by {frac2} which gives {unsimp_num}/{unsimp_den} {result_language} {result}"
    ]
    explanations_correct=shorten_list_for_train_test(explanations_correct,kind=which)
    explanations_correct_context_specific = [
        "Since {name1} {language3} {frac1} of the {context}, that is what remains and you then take {frac2} of that which means multiply the two fractions so {frac1}x{frac2} {result_language} {unsimp_num}/{unsimp_den} {result}"
    ]
    explanations_incorrect = [
        "You divide {frac1} by {frac2} {result_language} {unsimp_num}/{unsimp_den} {result_language} {result}",
        "I simply divide the fraction that {name1} {language3} by the amount {name2} {language3} which is {unsimp_num}/{unsimp_den} {result_language} {result}",
        "You divide the fractions so {frac1} divide {frac2} and that becomes {unsimp_num}/{unsimp_den} {result_language} {result}",
        "do {frac1}/{frac2} which is {unsimp_num}/{unsimp_den} {result_language} {result}",
        "Since we need to divide {frac2} by {frac1} we can flip and multiply to get {unsimp_num}/{unsimp_den} {result_language} {result}"
    ]
    explanations_incorrect=shorten_list_for_train_test(explanations_incorrect,kind=which)
    # Pick context
    use_context_specific = False
    if random.random() < 0.5:
        question = random.choice(questions)
        if random.random() < 0.5:
            use_context_specific = True
    else:
        question = random.choice(questions2)
    if force_non_context_specific:
        use_context_specific = False

    # Random picks
    name1 = random.choice(names)
    name2 = random.choice([n for n in names if n != name1])
    context = random.choice(contexts)
    language = random.choice(language1)
    language2 = past_tense_language[language]
    language3=past_tense_language2[language]
    try:
        context=questions_to_language_map[question]['context']
        language3=questions_to_language_map[question]['language3']
    except:
        pass
    question = question.format(
        name1=name1, name2=name2, frac1=frac1, frac2=frac2, language1=language, context=context, language2=language2
    )

    # Parse numbers
    num1, den1 = map(int, frac1.split('/'))
    num2, den2 = map(int, frac2.split('/'))

    result_language = random.choice(result_language_options)
    correct_num_unsimp, correct_den_unsimp = multiply_fractions_correctly(num1, den1, num2, den2)
    incorrect_num_unsimp, incorrect_den_unsimp, incorrect_unsimp_result_str, incorrect_result = multiply_fraction_division_misc(num1, den1, num2, den2)
    final_correct_answer = Fraction(correct_num_unsimp, correct_den_unsimp)
    final_correct_num = final_correct_answer.numerator
    final_correct_den = final_correct_answer.denominator

    # For corrected LaTeX formatting
    if scenario == 'correct':
        if final_correct_den == 1:
            answer_fmt = f"{final_correct_num}"
        else:
            if random.random()<0.5:
                answer_fmt = f"\\( \\frac{{{num1}}}{{{den1}}} \\times \\frac{{{num2}}}{{{den2}}} = \\frac{{{final_correct_num}}}{{{final_correct_den}}} \\)"
            else:
                answer_fmt = f"\\( \\frac{{{final_correct_num}}}{{{final_correct_den}}} \\)"
        if use_context_specific:
            explanation = random.choice(explanations_correct_context_specific).format(
                name1=name1, name2=name2, frac1=frac1, frac2=frac2, language2=language2,
                result_language=result_language, unsimp_num=correct_num_unsimp,
                unsimp_den=correct_den_unsimp, result=answer_fmt, context=context,language3=language3
            )
        else:
            explanation = random.choice(explanations_correct).format(
                name1=name1, name2=name2, frac1=frac1, frac2=frac2, language2=language2,
                result_language=result_language, unsimp_num=correct_num_unsimp,
                unsimp_den=correct_den_unsimp, result=answer_fmt, context=context,language3=language3
            )
        if random.random()<CHANGED_CAT_PROB:
          if incorrect_result.denominator == 1:
            answer_fmt = f"{incorrect_result.numerator}"
          else:
              if random.random()<0.5:
                  answer_fmt = f"\\( \\frac{{{num1}}}{{{den1}}} \\div \\frac{{{num2}}}{{{den2}}} = \\frac{{{incorrect_result.numerator}}}{{{incorrect_result.denominator}}} \\)"
              else:
                  answer_fmt = f"\\( \\frac{{{incorrect_result.numerator}}}{{{incorrect_result.denominator}}} \\)"
                  
          return {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["False_Correct"],
            "Misconception": ["No Misconception"],
            "MC_Answer": answer_fmt
        }
        return {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["True_Correct"],
            "Misconception": ["No Misconception"],
            "MC_Answer": answer_fmt
        }
    elif scenario == 'incorrect':
        if incorrect_result.denominator == 1:
            answer_fmt = f"{incorrect_result.numerator}"
        else:
            if random.random()<0.5:
                answer_fmt = f"\\( \\frac{{{num1}}}{{{den1}}} \\div \\frac{{{num2}}}{{{den2}}} = \\frac{{{incorrect_result.numerator}}}{{{incorrect_result.denominator}}} \\)"
            else:
                answer_fmt = f"\\( \\frac{{{incorrect_result.numerator}}}{{{incorrect_result.denominator}}} \\)"
        explanation = random.choice(explanations_incorrect).format(
            name1=name1, name2=name2, frac1=frac1, frac2=frac2, language2=language2,
            result_language=result_language, unsimp_num=incorrect_num_unsimp,
            unsimp_den=incorrect_den_unsimp, result=answer_fmt, context=context,language3=language3
        )
        if random.random()<CHANGED_CAT_PROB:
          if final_correct_den == 1:
            answer_fmt = f"{final_correct_num}"
          else:
              if random.random()<0.5:
                  answer_fmt = f"\\( \\frac{{{num1}}}{{{den1}}} \\times \\frac{{{num2}}}{{{den2}}} = \\frac{{{final_correct_num}}}{{{final_correct_den}}} \\)"
              else:
                  answer_fmt = f"\\( \\frac{{{final_correct_num}}}{{{final_correct_den}}} \\)"
          return {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["True_Misconception"],
            "Misconception": ["Division"],
            "MC_Answer": answer_fmt
        }
        return {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["False_Misconception"],
            "Misconception": ["Division"],
            "MC_Answer": answer_fmt
        }
    elif scenario == 'incorrect_incomplete':
        if random.random()<0.5:
            answer_fmt = f"\\( \\frac{{{num1}}}{{{den1}}} \\div \\frac{{{num2}}}{{{den2}}} = \\frac{{{incorrect_num_unsimp}}}{{{incorrect_den_unsimp}}} \\)"
        else:
            answer_fmt = f"\\( \\frac{{{incorrect_num_unsimp}}}{{{incorrect_den_unsimp}}} \\)"
        explanation = random.choice(explanations_incorrect).format(
            name1=name1,
            name2=name2,
            frac1=frac1,
            frac2=frac2,
            language2=language2,
            result_language='',
            unsimp_num=incorrect_num_unsimp,
            unsimp_den=incorrect_den_unsimp,
            context=context,
            language3=language3,
            result=f'So the answer is {incorrect_num_unsimp}/{incorrect_den_unsimp}'
        )
        return {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["False_Misconception"],
            "Misconception": ["Division", "Incomplete"],
            "MC_Answer": answer_fmt
        }
    elif scenario == 'incomplete':
        if random.random()<0.5:
            answer_fmt = f"\\( \\frac{{{num1}}}{{{den1}}} \\times \\frac{{{num2}}}{{{den2}}} = \\frac{{{correct_num_unsimp}}}{{{correct_den_unsimp}}} \\)"
        else:
            answer_fmt = f"\\( \\frac{{{correct_num_unsimp}}}{{{correct_den_unsimp}}} \\)"
        if use_context_specific:
            explanation = random.choice(explanations_correct_context_specific).format(
                name1=name1,
                name2=name2,
                frac1=frac1,
                frac2=frac2,
                language2="",
                context=context,
                result_language="",
                unsimp_num=correct_num_unsimp,
                unsimp_den=correct_den_unsimp,
                result="",
                language3=language3
            )
        else:
            explanation = random.choice(explanations_correct).format(
                name1=name1,
                name2=name2,
                frac1=frac1,
                frac2=frac2,
                language2=language2,
                result_language="",
                unsimp_num=correct_num_unsimp,
                unsimp_den=correct_den_unsimp,
                result="",
                context=context,
                language3=language3
            )
        return {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["False_Misconception"],
            "Misconception": ["Incomplete"],
            "MC_Answer": answer_fmt
        }

def find_lcm(a, b):
    """
    Calculates the Least Common Multiple (LCM) of two integers, a and b.

    Args:
        a (int): The first integer.
        b (int): The second integer.

    Returns:
        int: The LCM of a and b.
    """
    # Helper function to find the Greatest Common Divisor (GCD) using the Euclidean algorithm
    def find_gcd(x, y):
        # The GCD is the last non-zero remainder.
        while y:
            x, y = y, x % y
        return x

    # Handle the case where a or b is zero. The LCM is 0 if either is 0.
    if a == 0 or b == 0:
        return 0

    # Calculate the GCD
    gcd = find_gcd(a, b)

    # Apply the LCM formula: LCM(a, b) = (|a * b|) / GCD(a, b)
    # We use abs() to handle negative inputs, though LCM is typically defined for positive integers.
    # The result will always be a positive integer (or 0 if an input was 0).
    lcm = abs(a * b) // gcd

    return lcm
def augment_division(sample_size=50,which='train'):
    variants = []
    parameters = [('3/4','2/8'),('3/5','10/12'),('2/3','4/9'),('3/12','1/6')]*(sample_size//2)
    for i in range(sample_size//2):
        int1=random.randint(1,6)
        int2=int1*random.randint(1,4)
        int3=random.randint(int1+1,int1+5)*find_lcm(int1,int2)
        int4=random.randint(1,3)*find_lcm(int1,int2)
        
        param=(f"{int1}/{int2}",f"{int3}/{int4}")
        if int1<int2 and int3<int4:
            parameters.append(param)
    scenarios=['correct']*6+['incorrect']*18+['incorrect_incomplete']*6+['incomplete']*6

    for frac1, frac2 in parameters:
        for scenario in scenarios:
            variants.append(make_division(frac1, frac2, force_non_context_specific=False,scenario=scenario,which=which))
    return variants

def extract_decimal_digits(float_number):
    """
    Extracts all digits that appear after the decimal point of a float.

    Args:
        float_number (float): The floating-point number.

    Returns:
        str: A string containing only the digits after the decimal point.
             Returns an empty string if the number is an integer (e.g., 5.0).
    """
    # 1. Convert the float to a string
    num_str = str(float_number)

    # 2. Check if a decimal point exists
    if '.' in num_str:
        # 3. Split the string at the decimal point and take the second element (the part after the '.')
        _, decimal_part = num_str.split('.')
        return decimal_part
    else:
        # If there's no decimal point, the number is an integer
        return ""


