def make_floating_point(whole_part,integer,num_zeros):
    num1_whole_str=f"{whole_part}"
    num1_zero_part='0'*num_zeros
    dec_point='.'
    num1_whole_str=num1_whole_str+dec_point+num1_zero_part+str(integer)
    return float(num1_whole_str)
def augment_longer_is_bigger(which='train',sample_size=400):
  variants=make_longer_is_bigger(which=which,use_same_value_after_dec=True,sample_size=sample_size//2)
  variants.extend(make_longer_is_bigger(which=which,use_same_value_after_dec=False,sample_size=sample_size//2))
  return variants
def format_answer_wnb(num, den):
    return f"\\( \\frac{{{num}}}{{{den}}} \\)"

