def augment_shorter_is_bigger(sample_size=40,which='train'):
    variants = []
    scenarios=['incorrect']*18+['correct']*6
    for _ in range(sample_size):
        whole_part = random.randint(1, 10)
        # Generate two different decimal parts of length 1 or 2 digits for comparison
        integer1=1
        integer2=1
        while integer1==integer2:
            max_int=random.choice([10,100,10])
            integer1=random.randint(1,max_int)
            integer2=random.randint(1,max_int)
            if random.random()<1.3:
              integer1*=random.randint(100,1000)


        for scenario in scenarios:
            variants.append(make_shorter_is_bigger(whole_part, integer1, integer2, scenario,which=which))
    for _ in range(sample_size//4):
        whole_part = random.randint(1, 10)
        integer=random.randint(1,10)
        for scenario in scenarios:
          variants.append(make_shorter_is_bigger(whole_part, integer, integer, scenario=scenario,which=which))
    for _ in range(sample_size//8):
        whole_part = random.randint(1, 10)
        integer1=random.randint(1,10)
        integer2=0
        for scenario in scenarios:
          variants.append(make_shorter_is_bigger(whole_part, integer1, integer2, scenario=scenario,which=which))
    return variants



def make_not_variable(coefficient, extra_places, scenario='incorrect',which='train'):
    coef=coefficient
    coeficient=coef
    right_side=10*coef+extra_places
    variables=['x','y','z','w','a','b']
    variable=random.choice(variables)
    question_text = f"\\( {coefficient} {variable} = {right_side} \\) What is the value of \\( {variable} \\)?"
    correct_answer_unsimp=f"{right_side}/{coef}"
    correct_answer=int(right_side/coef)
    correct_answer_fraction=Fraction(right_side,coef)
    wrong_answer=extra_places

    ending_language = ['which is', 'which simplifies to', 'which equals', 'and that equals', 'and that simplifies to', 'which becomes']
    end_language=random.choice(ending_language)
    if scenario == 'correct':
        misconception=['No Misconception']
