def augment_not_variable(sample_size=80,which='train'):
    variants = []
    scenarios=['incomplete']+['incorrect']*18+['correct']*6
    for _ in range(sample_size):
        found=False
        while not found:
            coef = random.randint(1, 9)
            extra_places= random.randint(1,9)
            right_side=coef*10+extra_places
            if right_side%coef==0:
                found=True

        for scenario in scenarios:
            variants.append(make_not_variable(coef, extra_places, scenario,which=which))
    return variants
