def augment_adding_terms(sample_size=100,which='train'):
    variants = []
    scenarios=['correct']*6+ ['incorrect']*18
    for _ in range(sample_size):
        coef = random.randint(2, 10)
        answer = random.randint(1, 20)
        for i,scenario in enumerate(scenarios):
            if i%4==0:
              coef = random.randint(2, 10)
              answer = random.randint(1, 20)
            variants.append(make_adding_terms(coef, answer, scenario,which=which))
    return variants

def make_inverse_operation(coefficient, answer, scenario='incorrect',which='train'):
    # Your existing function here — unchanged
    product = coefficient * answer
    variables = ['x', 'y', 'z', 'w', 'a', 'b']
    variable = random.choice(variables)
    question_texts = [f"\\( {coefficient} {variable} = {product} \\) What is the value of \\( {variable} \\)?",
                     f"\\( {coefficient} {variable} = {product} \\) Solve for \\( {variable} \\)?"]
    question_text=random.choice(question_texts)

    if scenario == 'correct':
        explanations = [
            f"To solve for {variable}, divide both sides by {coefficient}, so {variable} = {product} \u00F7 {coefficient} = {answer}.",
            f"Since {coefficient} times {variable} equals {product}, do the opposite operation (division): {variable} = {product} \u00F7 {coefficient} = {answer}.",
            f"Divide {product} by {coefficient} and you get {variable} = {answer}.",
            f"Since the inverse of multiplying is dividing, I divide both sides by {coefficient} to get {answer}",
            f"Since the opposite of multiplying is dividing, I divide both sides by {coefficient} to get {answer}"

        ]
        explanations=shorten_list_for_train_test(explanations,which=which)
        explanation = random.choice(explanations)
        wrong_answer = product * coefficient
        category = ['True_Correct']
        if random.random()<CAT_CHANGE_PROB:
          mc_answer = f"\\({wrong_answer}\\)"
          category=['False_Correct']
        else:
          mc_answer = f"\\({answer}\\)"
        misconception = ['No Misconception']
    elif scenario == 'incorrect':
        wrong_answer = product * coefficient  # misconception: multiply instead of divide
        explanations = [
            f"I multiplied {product} by {coefficient} and got {wrong_answer}.",
            f"To find {variable}, I did {product} times {coefficient} which is {wrong_answer}.",
            f"I thought you multiply {product} by {coefficient} to get the answer, which is {wrong_answer}.",
            f"The answer is {wrong_answer} because {coefficient} × {product} = {wrong_answer}.",
            f"I saw that if you do {product} × {coefficient} you get {wrong_answer}, so that's the answer."
        ]
        explanations=shorten_list_for_train_test(explanations,which=which)
        explanation = random.choice(explanations)
        if random.random()<CHANGED_CATS_PROB:
          mc_answer = f"\\({answer}\\)"
          category = ['True_Misconception']
        else:
          category = ['False_Misconception']
          mc_answer = f"\\({wrong_answer}\\)"
        misconception = ['Inverse_operation']
    else:
        raise ValueError("scenario must be 'correct' or 'incorrect'")

    return {
        "QuestionText": question_text,
        "StudentExplanation": explanation,
        "Category": category,
        "Misconception": misconception,
        "MC_Answer": mc_answer
    }

# New function for subtraction equation misconception

def make_subtract_misconception_io(constant, answer, scenario='incorrect',which='train'):
    variables = ['x', 'y', 'z', 'w', 'a', 'b']
    variable = random.choice(variables)
    # equation: x - constant = result
    result = answer - constant
    question_texts = [f"\\( {variable} - {constant} = {result} \\) What is the value of \\( {variable} \\)?",
                      f"\\( {variable} - {constant} = {result} \\) Solve for \\( {variable} \\)?"]
    question_text=random.choice(question_texts)
    ending_language=['which equals','and that is','which simplifies to', 'and you get']
    end_language=random.choice(ending_language)
    if scenario == 'correct':
        explanations = [
            f"To solve for {variable}, add {constant} to both sides: {variable} = {result} + {constant} = {answer}.",
            f"Since {variable} minus {constant} equals {result}, add {constant} back to find {variable} = {answer}.",
            f"Add {constant} to {result} and get {answer}, so {variable} = {answer}.",
            f"Since the inverse of subtraction is addition, I add both sides by {constant} to get {answer}"
        ]
        explanations=shorten_list_for_train_test(explanations,which=which)
        explanation = random.choice(explanations)
        category = ['True_Correct']
        mc_answer = f"\\({answer}\\)"
        misconception = ['No Misconception']

    elif scenario == 'incorrect':
        # misconception: subtract instead of add
        wrong_answer = result - constant
        explanations = [
            f"I subtracted {constant} again from {result} and got {wrong_answer}.",
            f"I thought since {variable} minus {constant} equals {result}, I subtract {constant} again: {result} - {constant} = {wrong_answer}.",
            f"You subtract {constant} two times, so the answer is {wrong_answer}.",
            f"I subtract {constant} to both sides",
            f" I did {result}-{constant} {end_language} {wrong_answer}",
            f" I did {result}-{constant}={wrong_answer}"

        ]
        explanations=shorten_list_for_train_test(explanations,which=which)
        explanation = random.choice(explanations)
        category = ['False_Misconception']
        mc_answer = f"\\({wrong_answer}\\)"
        misconception = ['Inverse_operation']
    else:
        raise ValueError("scenario must be 'correct' or 'incorrect'")

    return {
        "QuestionText": question_text,
        "StudentExplanation": explanation,
        "Category": category,
        "Misconception": misconception,
        "MC_Answer": mc_answer
    }

