def lcm(a: int, b: int) -> int:
    return abs(a * b) // gcd(a, b)

def augment_denominator_only_change(sample_size=50,which='train'):
    num1, den1 = 1, 3
    num2, den2 = 2, 5
    variants = []
    scenarios=['incomplete']*3+['incorrect']*18+['correct']+['incorrect_incomplete']*3
    for _ in range(sample_size):
        for scenario in scenarios:#['correct', 'incorrect', 'incomplete', 'incorrect_incomplete']:
            num1, den1 = random.randint(2,4), random.randint(2,6)
            num2, den2 = random.randint(2,6), den1*random.randint(2,5)

            if num1==den1 or num2==den2:
                continue
            common_den=lcm(den1,den2)
            variants.append(make_denominator_only_change(num1,num2,den1,den2,common_den,scenario,which=which))
    return variants

