# --- Helper Functions (Required for the code to run) ---
def FORMAT_EXPRESSION(f1, f2, operator):
    """
    Formats the expression for MC_Answer, enclosing the entire expression
    in a single LaTeX block: \( \frac{A}{B} \text{ operator } \frac{C}{D} \).
    """
    f1_str = f"\\frac{{{f1.numerator}}}{{{f1.denominator}}}"
    f2_str = f"\\frac{{{f2.numerator}}}{{{f2.denominator}}}"
    # The entire expression is wrapped in a single \( \) block.
    return f"\\( {f1_str} {operator} {f2_str} \\)"
def FORMAT_EXPRESSION_PLUS(f1, f2):
    """Formats the expression for MC_Answer using the addition operator (+)."""
    return FORMAT_EXPRESSION(f1, f2, ' + ')

def FORMAT_EXPRESSION_DIVISION(f1, f2):
    """Formats the expression for MC_Answer using the division operator (\div)."""
    return FORMAT_EXPRESSION(f1, f2, ' \div ')

def FORMAT_ANSWER_SUBTRACTION2(value):
    """Formats the final numerical answer (used for calculating the correct expression)."""
    if isinstance(value, Fraction):
        if value.denominator == 1:
            return f"\\( {value.numerator} \\)"
        return f"\\( \\frac{{{value.numerator}}}{{{value.denominator}}} \\)"
    return f"\\( {value} \\)"

# --- Core Generator Function ---
def make_subtraction2(frac1_str, frac2_str, name1, name2, pronoun1, possessive1,
                      context, item, action, scenario='incorrect',which='train'):
    """
    Make a single Subtraction misconception variant where the MC_Answer is a number sentence.
    """
    f1 = Fraction(frac1_str)
    f2 = Fraction(frac2_str)

    # Required variables
    past_tense_map={'eaten':'ate', 'shared':'shared', 'given':'gave'}
    verb_map={'eaten':'eating', 'shared':'sharing', 'given':'giving'}
    past_tense_verb = past_tense_map[action]
    action_present = verb_map[action]

    # 1. Question Text
    question_context = context.format(
        name1=name1,
        name2=name2,
        pronoun1=pronoun1,
        possessive1=possessive1,
        frac1=FORMAT_ANSWER_SUBTRACTION2(f1),
        frac2=FORMAT_ANSWER_SUBTRACTION2(f2)
    )

    # Ensure the question asks for the operation/expression
    question_suffix = " Choose the number sentence that would solve the word problem."
    space=random.choice([' ', ''])
    question = question_context +space+ question_suffix

    # 2. Expression Answers
    correct_expression = FORMAT_EXPRESSION(f1, f2, ' \\times ') # e.g., \( \frac{2}{3} \times \frac{1}{3} \)
