# --- Augmentation Function ---
def augment_subtraction2(sample_size=800,which='train'):
    """
    Student uses subtraction when multiplication is needed.
    The MC_Answer is an expression.
    """
    variants = []

    original_names = [
        ('Sally', 'she', 'her'), ('Albert', 'he', 'his'), ('Emma', 'she', 'her'),
        ('John', 'he', 'his'), ('Esmeralda', 'she', 'her'), ('Luke', 'he', 'his'),
        ('Jerry', 'he', 'his'), ('Steven', 'he', 'his'), ('Maya', 'she', 'her'),
        ('Lucinda', 'she', 'her'), ('Jeremy', 'he', 'his'), ('Tom', 'he', 'his'),
        ('Alex', 'they', 'their'), ('Casey', 'they', 'their'), ('Taylor', 'they', 'their'),
    ]

    contexts = [
        ("{name1} has {frac1} of a whole cake. {name2} eats {frac2} of {possessive1} piece.", "cake", "eaten"),
        ("{name1} has {frac1} of a pizza. {pronoun1} gives {frac2} of {possessive1} piece to {name2}.", "pizza", "given"),
        ("{name1} owns {frac1} of a chocolate bar. {pronoun1} shares {frac2} of {possessive1} portion with {name2}.", "chocolate", "shared")
    ]

    # Fractions chosen to ensure subtraction is possible and yields a positive, non-zero result.
    fractions_set = [("2/3", "1/3"), ("3/4", "1/2"), ("4/5", "2/5"), ("5/6", "1/3"), ("5/8", "1/4"), ("7/10", "1/5"), ("3/5", "1/3")]

    # Generate 50% incorrect (Subtraction), 50% correct (Multiplication)
    scenarios_pool = ['incorrect'] * (sample_size // 2) + ['correct'] * (sample_size // 2)
    random.shuffle(scenarios_pool)

    # Generate samples up to the requested size
    for i in range(sample_size):

        scenario = scenarios_pool[i]

        # Ensure name sets are unique for the question
        names_pool = random.sample(original_names, 2)
        name1_set = names_pool[0]
        name2_set = names_pool[1]

        context_info, item, action = random.choice(contexts)
        frac1, frac2 = random.choice(fractions_set)

        variant = make_subtraction2(
            frac1, frac2,
            name1_set[0], name2_set[0], name1_set[1], name1_set[2],
            context_info, item, action,
            scenario=scenario,
            which=which
        )

        if variant:
            variants.append(variant)

    return variants
def make_inverse_operation3(coefficient, result, scenario='incorrect'):
    """
    Generate correct or incorrect answer for inverse operation problems.

    Args:
        coefficient: The coefficient of the variable (e.g., 2 in 2y = 24)
        result: The right side of the equation (e.g., 24 in 2y = 24)
        scenario: 'correct' or 'incorrect'

    Returns:
        The numerical answer (correct or with misconception)
    """
    if scenario == 'correct':
        # Correct: divide to isolate the variable
        return result // coefficient
    else:
        # Misconception: multiply instead of divide
        return result * coefficient

