def augment_wrongterm_misconception2(sample_size=1000,which='train'):
    """
    Generate a dataset of arithmetic sequence questions with correct and incorrect reasoning.
    Shows 4 visible patterns, asks for pattern n (where n >= 5).

    75% incorrect (demonstrating Wrong_term misconception)
    25% correct (showing proper arithmetic sequence reasoning)
    """
    variants = []

    contexts = [
        "dots",
        "marbles",
        "triangles",
        "squares",
        "pentagons"
    ]

    pattern_params = [
        (Fraction(1, 5), Fraction(1, 5)),
        (6, 2),
        (Fraction(1, 6), Fraction(1, 6)),
        (7, 3),
        (8, 5),
        (9, 4),
        (Fraction(2, 3), Fraction(2, 3))
    ]

    # Add random integer and fraction parameters
    for _ in range(sample_size // len(contexts)):
        int1 = random.randint(5, 20)
        int2 = random.randint(2, 8)
        pattern_params.append((int1, int2))
        tuple_frac = (Fraction(int1, int2), Fraction(int1, int2))
        pattern_params.append(tuple_frac)

    # Ask for patterns 5, 6, or 7 (since we show 1-4)
    pattern_indices = [ 6, 7,8,9]
    weights = [0.25, 0.75]  # 25% correct, 75% incorrect
    population = ['correct', 'incorrect']

    for context in contexts:
        for first_term, diff in pattern_params:
            for n in pattern_indices:
                kind = random.choices(population, weights=weights, k=1)[0]
                variant = make_wrongterm_variant2(context, first_term, diff, n, scenario=kind,which=which)
                variants.append(variant)

    return variants
def multiply_fractions_correctly(num1, den1, num2, den2):
    new_num = num1 * num2
    new_den = den1 * den2
    return new_num, new_den

def multiply_fraction_division_misc(num1, den1, num2, den2):
    # Division, as "multiply by reciprocal"
    new_num = int(num1 * den2)
    new_den = int(num2 * den1)
    return new_num, new_den, f"{num1}/{den1} divided by {num2}/{den2}", Fraction(new_num, new_den)


