def augment_division2(sample_size=1000,which='train'):
    """
    Generate multiple samples with the division misconception.
    Creates random fraction pairs and generates both correct and incorrect scenarios.
    """
    num_samples=sample_size
    samples = []

    # Common denominators for fraction problems
    denominators = [2, 3, 4, 5, 6, 8]


    for i in range(num_samples):
        # Generate random fractions
        
        den1 = random.choice(denominators)
        num1 = random.randint(1, den1 - 1)

        den2 = random.choice(denominators)
        num2 = 1
        if random.random()<0.2:
          num2=random.randint(1, den2 - 1)

        frac1 = f"{num1}/{den1}"
        frac2 = f"{num2}/{den2}"

        # Generate mix of correct and incorrect
        if i < num_samples // 3:
            if num1<den1 and num2<den2:
                sample = make_division2(frac1, frac2, scenario='incorrect',which=which)
            else:
                sample=None
        else:
            if num1<den1 and num2<den2:
                sample = make_division2(frac1, frac2, scenario='correct',which=which)
            else:
                sample=None
        if sample:
            samples.append(sample)

    return samples


# Helper functions for number words
def num2_to_words(n):
    words = {1: 'one', 2: 'two', 3: 'three', 4: 'four', 5: 'five', 6: 'six', 7: 'seven', 8: 'eight'}
    return words.get(n, str(n))

def ordinal(n):
    words = {2: 'half', 3: 'third', 4: 'fourth', 5: 'fifth', 6: 'sixth', 7: 'seventh', 8: 'eighth'}
    return words.get(n, f"{n}th")

def number_to_word(n):
    words = {2: 'two', 3: 'three', 4: 'four', 5: 'five', 6: 'six', 7: 'seven', 8: 'eight'}
    return words.get(n, str(n))
import random

def extract_decimal_digits(num):
    """Extract digits after decimal point as string"""
    str_num = str(num)
    if '.' in str_num:
        return str_num.split('.')[1]
    return None

