def augment_scale_certainty_misconception(sample_size=260,which='train'):
    """Generate samples with both Scale and Certainty misconceptions"""
    variants = []
    high_probs = [round(random.randint(70, 99) / 100, 2) for _ in range(sample_size // 2)] * 5
    tenths_only=[round(random.randint(7, 9) / 10, 2) for _ in range(sample_size // 5)]
    high_probs.extend(tenths_only)
    low_probs = []
    probabilities = high_probs + low_probs + [0] * int(sample_size * 0.15) + [1] * int(sample_size * 0.15)

    for prob in probabilities:
        scenario_choice = random.random()

        if scenario_choice < 0.3:
            variants.append(make_certainty2(prob, 'correct',which=which))
        elif scenario_choice < 0.0:
            variants.append(make_certainty2(prob, 'scale',which=which))
        else:
            variants.append(make_certainty2(prob, 'certainty',which=which))

    return variants
