import math
from typing import List, Dict, Tuple, Optional

def generate_fraction_equation_irrelevant(denom1: int, num2: int, denom2: int, answer: int,which='train') -> List[Tuple[str, str]]:
    """
    Generate irrelevant explanations for fraction equation problems like A/10 = 9/15.
    These mention true mathematical facts but don't explain the actual solution method.

    Args:
        denom1: Denominator of first fraction (where A is)
        num2: Numerator of second fraction
        denom2: Denominator of second fraction
        answer: The correct value of A

    Returns:
        List of (explanation, answer) tuples
    """
    explanations = []

    # Calculate GCD for generating wrong answers
    gcd = math.gcd(num2, denom2)

    # Pattern 1: Times table references (mentions divisibility but not the equation)
    # Use GCD as wrong answer since it's a related but incorrect value
    times_table_patterns = [
        (f"Because it goes into {num2} and {denom2}.", str(gcd)),
        (f"{num2} and {denom2} are both in the {gcd} times tables.", str(gcd)),
        (f"Because {gcd} is in the same times table as {num2}.", str(gcd)),
        (f"I think you have to go in the {gcd} times tables.", str(gcd)),
        (f"There are {num2} and {denom2} in the {gcd} times table.", str(gcd)),
        (f"{gcd} is in the {num2} times table so {gcd} times {gcd} = {num2}.", str(gcd)),
    ]
    times_table_patterns=shorten_list_for_train_test(times_table_patterns,which=which)
    # Only add if GCD is different from correct answer
    if gcd != answer:
        explanations.extend(times_table_patterns)

    # Pattern 2: Multiplication focus (fixates on repeated multiplication)
    # Try to find a number that when squared equals num2
    sqrt_num2 = int(math.sqrt(num2))
    if sqrt_num2 * sqrt_num2 == num2 and sqrt_num2 != answer:
        wrong_mult_answer = sqrt_num2
    else:
        # Use a related but wrong value
        wrong_mult_answer = gcd if gcd != answer else (answer + 1 if answer < 10 else answer - 1)

    mult_patterns = [
        (f"I think this because {wrong_mult_answer} times {wrong_mult_answer} is {num2}.", str(wrong_mult_answer)),
        (f"Because {wrong_mult_answer} x {wrong_mult_answer} = {wrong_mult_answer * wrong_mult_answer} and so that's the numerator for {denom1}.", str(wrong_mult_answer)),
        (f"I answered {wrong_mult_answer} because you times {wrong_mult_answer} by {wrong_mult_answer}.", str(wrong_mult_answer)),
        (f"If we times it {wrong_mult_answer} times, it will be {num2}.", str(wrong_mult_answer)),
        (f"{wrong_mult_answer} is the only number which could make {num2}.", str(wrong_mult_answer)),
    ]
    mult_patterns=shorten_list_for_train_test(mult_patterns,which=which)
    explanations.extend(mult_patterns)

    # Pattern 3: Division focus (mentions factors but doesn't solve)
    # Use a factor of num2 that's not the answer
    factors_num2 = [i for i in range(2, num2 + 1) if num2 % i == 0 and i != answer]
    wrong_div_answer = factors_num2[0] if factors_num2 else (gcd if gcd != answer else num2)

    div_patterns = [
        (f"Because {num2} divided by {wrong_div_answer} is {num2 // wrong_div_answer}.", str(wrong_div_answer)),
        (f"Go work out what goes into {num2} which is {wrong_div_answer}.", str(wrong_div_answer)),
        (f"I think it's because {wrong_div_answer} goes into {num2}.", str(wrong_div_answer)),
        (f"Because {wrong_div_answer} fits into {num2} {num2 // wrong_div_answer} times.", str(wrong_div_answer)),
    ]
    div_patterns=shorten_list_for_train_test(div_patterns,which=which)
    explanations.extend(div_patterns)

    # Pattern 4: Simplification confusion (mentions common factors)
    # Create wrong answers based on simplification
    wrong_simplify = answer * 2 if answer * 2 != answer else answer + 1

    simplify_patterns = [
        (f"I think this because both can be divided by three.", str(3)),
        (f"{num2} and {denom2} are in the {gcd} times tables so {wrong_simplify}/{denom1} is the equivalent fraction.", str(wrong_simplify)),
        (f"A common multiple of these two numbers is {gcd}, then the simplified number for A will be {gcd}.", str(gcd)),
    ]
    simplify_patterns=shorten_list_for_train_test(simplify_patterns,which=which)
    # Only add patterns with wrong answers
    explanations.extend([(exp, ans) for exp, ans in simplify_patterns if int(ans) != answer])

    # Pattern 5: Trial and error
    wrong_ans = answer + 1
    trial_patterns = [
        (f"I've already tried {wrong_ans} but it wasn't that so I knew the closest number to {wrong_ans} is {answer} so I did {answer}.", str(answer)),
    ]
    explanations.extend(trial_patterns)

    # Pattern 6: Vague reasoning
    vague_patterns = [
        (f"{answer} seemed like the right answer.", str(answer)),
        (f"Because {answer} makes sense.", str(answer)),
    ]
    explanations.extend(vague_patterns)

    return explanations


def generate_fraction_of_amount_irrelevant(total: int, numerator: int, denominator: int, answer: int,which='train') -> List[Tuple[str, str]]:
    """
    Generate irrelevant explanations for fraction of amount problems like "3/5 of 120".

    Args:
        total: The total amount (e.g., 120 counters)
        numerator: Numerator of the fraction (e.g., 3)
        denominator: Denominator of the fraction (e.g., 5)
        answer: The correct answer

    Returns:
        List of (explanation, answer) tuples
    """
    explanations = []

    # Pattern 1: Times table focus
    times_table_patterns = [
        (f"I used the {denominator} times table and got {numerator * denominator}.", str(numerator * denominator)),
        (f"Because I did my {denominator} times table all the way up to {total}.", str(numerator * denominator)),
        (f"I think this because I used the {denominator} times tables.", str(numerator * denominator)),
    ]
    times_table_patterns=shorten_list_for_train_test(times_table_patterns,which=which)
    explanations.extend(times_table_patterns)

    # Pattern 2: Multiple confusion (picks a multiple of denominator)
    # Find some multiples of the denominator
    multiples = [denominator * i for i in range(1, min(10, total // denominator + 1))]
    if multiples:
        mult_val = random.choice(multiples)
        multiple_patterns = [
            (f"I know because {mult_val} is the only answer that was a multiple of {denominator}.", str(mult_val)),
            (f"Because it's the only number they both go into.", str(mult_val)),
        ]
        explanations.extend(multiple_patterns)

    # Pattern 3: Percentage confusion
    percentage = (numerator / denominator * 100)
    pct_int = int(percentage)
    pct_patterns = [
        (f"I think this is the answer because if you times {numerator}/{denominator} by 20 you get {pct_int}/100. {pct_int}/100={pct_int}% therefore this is the answer.", str(pct_int)),
    ]
    explanations.extend(pct_patterns)

    # Pattern 4: Vague reasoning
    vague_patterns = [
        (f"Because {answer} makes sense for this problem.", str(answer)),
        (f"It looked correct to me.", str(answer)),
    ]
    explanations.extend(vague_patterns)

    return explanations


def extract_fraction_equation_params(question_text: str) -> Optional[Dict]:
    """
    Extract parameters from fraction equation questions like:
    '\\( \\frac{A}{10}=\\frac{9}{15} \\) What is the value of \\( A \\)?'

    Returns dict with keys: denom1, num2, denom2, answer
    """
    import re

    # Pattern: \frac{A}{denom1}=\frac{num2}{denom2}
    pattern = r'\\frac\{A\}\{(\d+)\}=\\frac\{(\d+)\}\{(\d+)\}'
    match = re.search(pattern, question_text)

    if match:
        denom1 = int(match.group(1))
        num2 = int(match.group(2))
        denom2 = int(match.group(3))

        # Calculate answer: A/denom1 = num2/denom2 => A = (num2 * denom1) / denom2
        answer = (num2 * denom1) // denom2

        return {
            'denom1': denom1,
            'num2': num2,
            'denom2': denom2,
            'answer': answer,
            'type': 'fraction_equation'
        }

    return None


def extract_fraction_of_amount_params(question_text: str) -> Optional[Dict]:
    """
    Extract parameters from fraction of amount questions like:
    'A box contains \\( 120 \\) counters... \\( \\frac{3}{5} \\) of the counters are red.'

    Returns dict with keys: total, numerator, denominator, answer
    """
    import re

    # Pattern: total amount
    total_pattern = r'contains\s+\\?\(?\\?\s*(\d+)\s*\\?\)?'
    total_match = re.search(total_pattern, question_text)

    # Pattern: fraction
    frac_pattern = r'\\frac\{(\d+)\}\{(\d+)\}'
    frac_match = re.search(frac_pattern, question_text)

    if total_match and frac_match:
        total = int(total_match.group(1))
        numerator = int(frac_match.group(1))
        denominator = int(frac_match.group(2))

        # Calculate answer
        answer = (total * numerator) // denominator

        return {
            'total': total,
            'numerator': numerator,
            'denominator': denominator,
            'answer': answer,
            'type': 'fraction_of_amount'
        }

    return None


def generate_irrelevant_samples(sample_size: int = 500,which='train') -> List[Dict]:
    """
    Generate synthetic irrelevant misconception samples.
    Creates new questions with irrelevant explanations.

    Args:
        sample_size: Number of samples to generate

    Returns:
        List of dictionaries with QuestionText, StudentExplanation, MC_Answer, Misconception, Category
    """
    variants = []

    # Question templates with parameter ranges
    fraction_equation_configs = [
        # (denom1, num2, denom2) where answer = (num2 * denom1) / denom2
        (10, 9, 15),  # A/10 = 9/15, A = 6
        (10, 6, 15),  # A/10 = 6/15, A = 4
        (8, 6, 12),   # A/8 = 6/12, A = 4
        (12, 8, 16),  # A/12 = 8/16, A = 6
        (15, 12, 20), # A/15 = 12/20, A = 9
        (20, 15, 25), # A/20 = 15/25, A = 12
        (6, 4, 8),    # A/6 = 4/8, A = 3
        (14, 10, 20), # A/14 = 10/20, A = 7
    ]

    fraction_of_amount_configs = [
        # (total, numerator, denominator)
        (120, 3, 5),   # 3/5 of 120 = 72
        (150, 2, 5),   # 2/5 of 150 = 60
        (100, 3, 4),   # 3/4 of 100 = 75
        (180, 2, 3),   # 2/3 of 180 = 120
        (200, 3, 10),  # 3/10 of 200 = 60
        (90, 2, 9),    # 2/9 of 90 = 20
        (240, 5, 8),   # 5/8 of 240 = 150
        (160, 3, 8),   # 3/8 of 160 = 60
    ]

    for _ in range(sample_size):
        # Randomly choose question type
        problem_type=None
        if random.random() < 0.5:
            problem_type=14
            # Generate fraction equation question
            denom1, num2, denom2 = random.choice(fraction_equation_configs)
            answer = (num2 * denom1) // denom2

            question_text = f"\\( \\frac{{A}}{{{denom1}}}=\\frac{{{num2}}}{{{denom2}}} \\) What is the value of \\( A \\)?"

            explanations = generate_fraction_equation_irrelevant(denom1, num2, denom2, answer,which=which)

        else:
            problem_type=4
            # Generate fraction of amount question
            total, numerator, denominator = random.choice(fraction_of_amount_configs)
            answer = (total * numerator) // denominator

            question_text = f"A box contains \\( {total} \\) counters. The counters are red or blue. \\( \\frac{{{numerator}}}{{{denominator}}} \\) of the counters are red.\\nHow many red counters are there?"

            explanations = generate_fraction_of_amount_irrelevant(total, numerator, denominator, answer,which=which)

        if not explanations:
            continue

        # Pick a random explanation
        explanation_text, wrong_answer = random.choice(explanations)

        # Determine if this is a true or false misconception
        mc_answer_formatted = f"\\( {wrong_answer} \\)"
        correct_formatted = f"\\( {answer} \\)"

        if str(wrong_answer) == str(answer):
            category = ['True_Misconception']  # Right answer, wrong reasoning
        else:
            category = ['False_Misconception']  # Wrong answer, wrong reasoning

        variant = {
            "QuestionText": question_text,
            "StudentExplanation": explanation_text,
            "Category": category,
            "Misconception": ["Irrelevant"],
            "MC_Answer": mc_answer_formatted,
            "problem_type":problem_type
        }

        variants.append(variant)

    return variants


def augment_irrelevant_from_existing2(existing_data: List[Dict], sample_size: int = 500) -> List[Dict]:
    """
    Generate irrelevant variants from existing questions using the specific patterns.

    Args:
        existing_data: List of existing question dictionaries with 'QuestionText' and 'MC_Answer'
        sample_size: Number of variants to generate

    Returns:
        List of generated variant dictionaries
    """
    variants = []

    for _ in range(sample_size):
        if not existing_data:
            break

        random_sample = random.choice(existing_data)
        question_text = random_sample.get('QuestionText', '')

        # Try to identify question type and extract parameters
        params = extract_fraction_equation_params(question_text)
        if not params:
            params = extract_fraction_of_amount_params(question_text)

        if not params:
            continue

        # Generate explanations based on question type
        if params['type'] == 'fraction_equation':
            explanations = generate_fraction_equation_irrelevant(
                params['denom1'],
                params['num2'],
                params['denom2'],
                params['answer']
            )
        elif params['type'] == 'fraction_of_amount':
            explanations = generate_fraction_of_amount_irrelevant(
                params['total'],
                params['numerator'],
                params['denominator'],
                params['answer']
            )
        else:
            continue

        if not explanations:
            continue

        # Pick a random explanation
        explanation_text, wrong_answer = random.choice(explanations)

        # Determine category
        mc_answer_formatted = f"\\( {wrong_answer} \\)"
        correct_formatted = f"\\( {params['answer']} \\)"

        if str(wrong_answer) == str(params['answer']):
            category = ['True_Misconception']
        else:
            category = ['False_Misconception']

        variant = {
            "QuestionText": question_text,
            "StudentExplanation": explanation_text,
            "Category": category,
            "Misconception": ["Irrelevant"],
            "MC_Answer": mc_answer_formatted
        }

        variants.append(variant)

    return variants
def make_multiplying_instead_of_dividing(original_workers, new_workers, total_time,which='train'):
    """
    Creates work-rate problems where students multiply by the factor instead of dividing.
    This is the inverse proportion error: they apply direct proportion logic to inverse problems.

    original_workers: int, number of workers initially
    new_workers: int, new number of workers working on the same task
    total_time: int, time taken by original_workers

    Returns:
      A dict with question, explanation, answer, misconception, and category
    """
    tasks = ["build a wall", 'make lemonade', 'build a fence', 'clean a pool', 'move supplies',
             'lay brick', 'build a water fountain', 'clean the house']
    workers_strs = ['workers', "people", 'employees']
    time_units_list = ["hours", 'minutes', 'seconds', 'days', 'weeks']

    task = random.choice(tasks)
    workers_str = random.choice(workers_strs)
    time_unit = random.choice(time_units_list)

    # Calculate the factor
    factor = new_workers / original_workers
    factor=int(factor)
    # Wrong answer: multiply instead of divide
    wrong_answer_multiply = total_time * factor
    if random.random() < 0.75:
        wrong_answer_multiply = int(wrong_answer_multiply)

    # Correct answer
    correct_answer = total_time / factor
    if random.random() < 0.75:
        correct_answer = int(correct_answer)

    # Per-person time (used in some explanations)
    per_person_time = total_time / original_workers
    if random.random() < 0.75:
        per_person_time = int(per_person_time)

    language1 = random.choice(['about', 'roughly'])
    language2 = random.choice(['would it take', 'is it going to take'])

    questions = [
        (f"It takes {original_workers} {workers_str} a total of {total_time} {time_unit} to {task}. "
         f"How long would it take if {new_workers} {workers_str} did the same {task}?"),
        (f'If {original_workers} {workers_str} can {task} in {total_time} {time_unit} then how long {language2} {new_workers} {workers_str}'),
        (f"{original_workers} {workers_str} take {language1} {total_time} {time_unit} to {task}, how long {language2} {new_workers} {workers_str}")
    ]
    question = random.choice(questions)

    # Wrong explanations - multiply by factor
    explanations_wrong = [
        # Direct multiplication
        f"I did {new_workers} / {original_workers} = {factor} and then I multiplied that by {total_time}",
        f"{total_time} / {original_workers} = {per_person_time} then you times it by {new_workers} = {wrong_answer_multiply}",
        f"Times by {factor}. I worked it out with box method",
        f"Because the sum is {total_time} times by {factor}",
        f"It takes 1 person {per_person_time} then you times it by {new_workers} which is {wrong_answer_multiply}",
        f"Times all of it by {factor} to get {wrong_answer_multiply}",
        f"I think this because {total_time} times {factor} is {wrong_answer_multiply} {time_unit}",
        f"I worked out that one person would take {per_person_time} {time_unit} and times it by {new_workers} to give me my answer",

        # Factor reasoning but wrong direction
        f"I think this because you times {total_time} by {factor} because {original_workers} x {factor} is {new_workers} and you do the same to both sides. And the answer is {wrong_answer_multiply}",
        f"Because you do {total_time} divided by {original_workers} is {per_person_time} and then {per_person_time} x {new_workers} = {wrong_answer_multiply} and that is how long it takes {new_workers} {workers_str}",
        f"{total_time} x {factor} = {wrong_answer_multiply}. {original_workers} x {factor} = {new_workers} so you can just times {total_time} by {factor}",
        f"I think this because {new_workers} is in the {original_workers} times tables so you can divide {new_workers} by {original_workers} and get the number you times by. Then I did {original_workers} x {factor} = {new_workers} {workers_str} and then on the other side {total_time} x {factor} = {wrong_answer_multiply}",
        f"From {original_workers} to get to {new_workers} you would be multiplying by {factor}, so you times by {factor} on the other side to end up with {wrong_answer_multiply}",

        # Per-person calculation then multiply
        f"If 1 person builds it would take {per_person_time} so {per_person_time} x {new_workers} = {wrong_answer_multiply}",
        f"This is because {new_workers} divided by {original_workers} equals to {factor} then you multiply {total_time} by {factor} which will equal to {wrong_answer_multiply} {time_unit}",
        f"{total_time} divided by {original_workers}, which gives you the amount that each person does, then do that times {new_workers}",
        f"I think the answer is {wrong_answer_multiply} since {total_time} x {new_workers} divided by {original_workers} = {wrong_answer_multiply}",
        f"{new_workers} divided by {original_workers} equals to {factor}. Then you multiply {total_time} by {factor} which will equal to {wrong_answer_multiply} {time_unit}",
        f"So you times it by {new_workers} because if you divide {original_workers} into {total_time} you get {per_person_time} so you then times by {new_workers}",

        # Ratio/constant reasoning (wrong)
        f"{total_time} times by {factor} gives the remainder",
        f"You have to find one and then times that by {new_workers}",
        f"The answer is {per_person_time} because {total_time} divided by {original_workers} is equal to {per_person_time}. {per_person_time} x {new_workers} is {wrong_answer_multiply}",
        f"I think this because I worked out the k constant is {factor} so {total_time} x {factor} = {wrong_answer_multiply} {time_unit}",
        f"{total_time}/{original_workers} = {per_person_time} (per person) therefore if there were {new_workers} {workers_str}... {per_person_time} * {new_workers} = {wrong_answer_multiply}",
        f"I think this because you do {total_time} divided by {original_workers} to get {per_person_time} then times that by the {new_workers} to get {wrong_answer_multiply}",
        f"I think this because {new_workers} × {original_workers} = {factor} which means {original_workers} x {factor} = {new_workers} so you just have to times {total_time} by {factor} and you get this answer",
        f"I think this because {new_workers} ÷ {original_workers} = {factor} so I have to multiply {total_time} {time_unit} by {factor} which is {wrong_answer_multiply} {time_unit}",
        f"I think the answer is {wrong_answer_multiply} {time_unit} because first you need to convert the question into ratio is {original_workers} {workers_str}:{total_time} {time_unit} and {new_workers}:?. The factor is {factor} so times {total_time} by {factor} which is {wrong_answer_multiply}",
    ]
    explanations_wrong=shorten_list_for_train_test(explanations_wrong,which=which)
    # Correct explanations (from your base_rate function)
    language4 = random.choice(['factor', 'multiplier'])
    language5 = random.choice(['number', 'amount'])

    explanations_correct = [
        (f"Since there are {factor} times more {workers_str}, it takes 1/{factor} the time: "
         f"{total_time} ÷ {factor} = {correct_answer} {time_unit}"),
        (f"I divided {new_workers}/{original_workers} which gave a {language4} of {factor}, so you can divide the total time by this factor, "
         f"therefore {total_time}/{factor} which is {correct_answer} {time_unit}"),
        f"With {factor} times more {workers_str}, it takes 1/{factor} the time: {total_time} ÷ {factor} = {correct_answer}",
        f"Because {original_workers} x {factor} = {new_workers} so {total_time} divided by {factor} is {correct_answer}",
        f"You do {original_workers} x {factor} = {new_workers} so you do {total_time} divided by {factor} = {correct_answer}",
        f"They are inversely proportional. {factor} times as many {workers_str}, so takes 1/{factor} of the time. {total_time}/{factor} = {correct_answer} {time_unit}",
    ]
    explanations_correct=shorten_list_for_train_test(explanations_correct,which=which)
    if random.random() < 0.75:
        # Generate misconception (75% of the time)
        explanation = random.choice(explanations_wrong)
        variant = {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["False_Misconception"],
            "Misconception": ["Multiplying_by_4"],
            "MC_Answer": f"\\( {wrong_answer_multiply} \\) {time_unit}"
        }
    else:
        # Generate correct answer (25% of the time)
        explanation = random.choice(explanations_correct)
        variant = {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["True_Correct"],
            "Misconception": ["No Misconception"],
            "MC_Answer": f"\\( {correct_answer} \\) {time_unit}"
        }

    return variant
def augment_multiplying_by_4_two(sample_size=30,which='train'):
    """Student multiplies when should divide (work rate problems) + correct examples"""
    variants = []
    for _ in range(sample_size):
        workers=random.randint(2,5)

        new_workers=workers*4
        factor=find_lcm(workers,new_workers)
        total_time=random.randint(2,7)*factor
        for _ in range(sample_size):
          variant=make_multiplying_instead_of_dividing(workers,new_workers,total_time,which=which)
          variants.append(variant)
    return variants
def make_unknowable2(value, scenario='incorrect', which='train'):
    """
    Generate questions about regular polygons where students incorrectly
    claim there's not enough information to determine the number of sides.

    Args:
        value: interior angle in degrees
        scenario: 'correct' or 'incorrect'
        which: 'train' or 'test'
    """
    # Polygon name dictionary
    polygon_names = {
        3: 'triangle',
        4: 'quadrilateral',
        5: 'pentagon',
        6: 'hexagon',
        7: 'heptagon',
        8: 'octagon',
        9: 'nonagon',
        10: 'decagon',
        11: 'hendecagon',
        12: 'dodecagon'
    }

    # Calculate the correct answer
    one_eighty_subtract_angle = 180 - value
    unsimp_correct_answer = f"360/{one_eighty_subtract_angle}"
    correct_answer = 360 / one_eighty_subtract_angle
    polygon_name = polygon_names.get(int(correct_answer), f"{int(correct_answer)}-sided polygon")

    # Determine angle type
    if value > 90:
        language1 = 'obtuse'
    elif value == 90:
        language1 = 'right'
    else:
        language1 = 'acute'

    # Question templates - all mention "regular polygon"
    questions = [
        "This is part of a regular polygon. How many sides does it have? [Image: A diagram showing an {language1} angle labelled {angle} degrees]",
        "The diagram shows an angle that is one of the interior angles of a regular polygon. [Image: A diagram showing an {language1} angle labelled {angle} degrees]. How many sides does the regular polygon have?",
        "[Image: A diagram showing an {language1} angle labelled {angle} degrees], this is part of a regular polygon. How many sides does the polygon have?"
    ]

