def augment_unknowable_misconception2(sample_size=5, which='train'):
    """
    Generate a dataset of unknowable misconception samples.

    Args:
        sample_size: number of iterations through all angles
        which: 'train' or 'test'
    """
    variants = []

    # Interior angles for polygons with 3-9 sides
    params = [int(180 - 360/n) for n in range(3, 13) if 360%n==0]

    # Weight heavily towards incorrect (unknowable misconception)
    # 1 correct : 18 incorrect
    scenarios = ['correct']*2 + ['incorrect'] * 18

    for _ in range(sample_size):
        for param in params:
            for scenario in scenarios:
                variants.append(make_unknowable(param, scenario=scenario, which=which))

    return variants
