def augment_shorter_is_bigger2(sample_size=40, which='train'):
    variants = []
    scenarios = ['incorrect'] * 18 + ['correct'] * 2
    for _ in range(sample_size):
        whole_part = random.randint(1, 10)
        # Generate three different decimal parts
        integer1 = 1
        integer2 = 1
        integer3 = 1
        while integer1 == integer2 or integer1 == integer3 or integer2 == integer3:
            max_int = random.choice([10, 100, 10])
            integer1 = random.randint(1, max_int)
            integer2 = random.randint(1, max_int)
            integer3 = random.randint(1, max_int)
            if random.random() < 0.3:
                integer1 *= random.randint(100, 1000)

        for scenario in scenarios:
            variants.append(make_shorter_is_bigger2(whole_part, integer1, integer2, integer3, scenario, which=which))

    for _ in range(sample_size // 4):
        whole_part = random.randint(1, 10)
        integer = random.randint(1, 10)
        for scenario in scenarios:
            variants.append(make_shorter_is_bigger2(whole_part, integer, integer, integer, scenario=scenario, which=which))

    for _ in range(sample_size // 8):
        whole_part = random.randint(1, 10)
        integer1 = random.randint(1, 10)
        integer2 = 0
        integer3 = random.randint(1, 10)
        for scenario in scenarios:
            variants.append(make_shorter_is_bigger2(whole_part, integer1, integer2, integer3, scenario=scenario, which=which))

    return variants
