def augment_whole_number_bias_three(sample_size=50, which='train'):
    variants = []
    scenarios = ['incorrect'] * 18
    for _ in range(sample_size):
        if random.random() < 0.30:
            whole_num1 = random.randint(1, 100)
            whole_num2 = random.randint(1, 100)
            # Make sure the two whole numbers are different
            while whole_num1 == whole_num2:
                whole_num2 = random.randint(1, 100)
            # Generate decimal number with more chance to be sometimes bigger, sometimes smaller
            decimal_num = round(random.uniform(0, max(whole_num1, whole_num2) + 100), 2)
        else:
            integer = random.randint(1, 100)
            whole_num1 = integer
            whole_num2 = random.randint(1, 100)
            # Make sure the two whole numbers are different
            while whole_num1 == whole_num2:
                whole_num2 = random.randint(1, 100)
            decimal_num = integer + random.choice([random.randint(1, 99) / random.choice([100, 1000])])

        if decimal_num == round(decimal_num):
            continue

        for scenario in scenarios:
            variants.append(make_whole_number_bias_three(whole_num1, whole_num2, decimal_num, scenario, which=which))

    return variants
