def calculate_total(price: float, quantity: int = 1, tax_rate: float = 0.05) -> float:
    """Calculates the final cost including tax."""
    return (price * quantity) * (1 + tax_rate)

def process_data(data: List[Dict[str, Any]], filter_key: str) -> Union[List[Any], None]:
    """Processes a list of dictionaries based on a filter key."""
    if not data:
        return None
    return [d.get(filter_key) for d in data if filter_key in d]

