# --- Function to print the detailed signature ---

def print_function_details(func_list: List[Callable]) -> None:
    """Prints the name, parameters, and return type for each function in a list."""

    print("--- Function Signature Report ---")

    for func in func_list:
        try:
            # 1. Get the signature object
            sig = inspect.signature(func)

            # 2. Extract the function name
            func_name = func.__name__

            # 3. Format Parameters
            params = []
            for name, param in sig.parameters.items():
                # Get the type annotation, or '?' if none is provided
                annotation = str(param.annotation).replace("'", "")

                # Check for default value
                default_val = f" = {param.default}" if param.default is not inspect.Parameter.empty else ""

                params.append(f"{name}: {annotation}{default_val}")

            parameters_str = ", ".join(params)

            # 4. Extract Return Annotation
            return_annotation = str(sig.return_annotation).replace("'", "")
            if return_annotation == "<class 'NoneType'>" or return_annotation == "None":
                 return_type_str = "" # Often simplified for better display
            elif return_annotation == inspect.Signature.empty:
                return_type_str = " -> ?"
            else:
                return_type_str = f" -> {return_annotation}"


            # 5. Print the formatted output
            print(f"\nFunction: {func_name}")
            print(f"Signature: ({parameters_str}){return_type_str}")
            print(f"Docstring: {func.__doc__}")

        except ValueError as e:
            # Catches errors if the object is not a valid callable (e.g., a built-in function
            # without a Python signature)
            print(f"\nCould not get signature for {func.__name__}: {e}")
def make_certainty(probability, scenario='incorrect',which='train'):
    """Generate a question and misconception example around the Certainty misconception.

    Args:
        probability (float): Probability value between 0 and 1.
        scenario (str): Either 'correct' or 'incorrect' to generate a proper or misconception sample.

    Returns:
        dict: Sample with QuestionText, StudentExplanation, Category, Misconception, MC_Answer.
    """
    question = (
        f"The probability of an event occurring is \\( {probability} \\).\n\n"
        "Which of the following most accurately describes the likelihood of the event occurring?"
    )

    correct_label = "Very likely" if probability >= 0.8 else "Likely"
    incorrect_label = "Certain"  # Misconception often that high prob means certain

    correct_explanations = [
        f"A probability of {probability} indicates a high likelihood but not absolute certainty.",
        f"Since {probability} is less than 1, the event is very likely but not certain.",
        f"A probability of {probability} means there's a {int(probability * 100)}% chance, which is high but not guaranteed."
    ]
    correct_explanations=shorten_list_for_train_test(correct_explanations,kind='train')
    certainty_misconceptions = [
        f"{probability} is very close to 1, so the event is basically certain.",
        f"Because the probability is near 1, it means the event will almost certainly happen.",
        f"The chance is {probability}, which is considered certain because it's so high.",
        f"With a probability of {probability}, it’s safe to say the event is certain."
    ]
    certainty_misconceptions=shorten_list_for_train_test(certainty_misconceptions,kind='train')
    if scenario == 'correct':
        explanation = random.choice(correct_explanations)
        return {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["True_Correct"],
            "Misconception": ["No Misconception"],
            "MC_Answer": correct_label
        }
    else:
        explanation = random.choice(certainty_misconceptions)
        return {
            "QuestionText": question,
            "StudentExplanation": explanation,
            "Category": ["False_Misconception"],
            "Misconception": ["Certainty"],
            "MC_Answer": incorrect_label
        }


def augment_certainty_misconception(sample_size=950,which='train'):
    probabilities = [round(random.randint(1,100)/100,2) for _ in range(sample_size)]
    variants = []
    for prob in probabilities:
        if random.random()<0.3:
            variants.append(make_certainty(prob, scenario='correct',which=which))
        variants.append(make_certainty(prob, scenario='incorrect',which=which))
    return variants
