def print_user_defined_variables():
    """
    Prints the name and value of global variables that are NOT functions,
    modules, or standard system variables.
    """
    print("--- User-Defined Global Variables ---")

    global_vars = globals()

    # Track if any variables are printed
    found_vars = False

    for name, value in sorted(global_vars.items()):

        # 1. Skip system/dunder names (e.g., __name__, __doc__)
        if name.startswith('__') and name.endswith('__'):
            continue

        # 2. Skip imported modules
        if isinstance(value, types.ModuleType):
            continue

        # 3. Skip functions (including lambda functions)
        if isinstance(value, types.FunctionType):
            continue

        # 4. Skip classes (which are also often in the global scope)
        if isinstance(value, type):
            continue

        # If it passes all the checks, it's likely a user-defined variable (list, int, str, dict, etc.)

        # Truncate long values for readability
        value_repr = repr(value)
        if len(value_repr) > 100:
            value_repr = value_repr[:97] + "..."

        print(f"Variable: {name} = {value_repr}")
        found_vars = True

    if not found_vars:
        print("No non-function/non-module global variables found.")
import re
from typing import Dict, List
import re
from collections import defaultdict
from typing import Dict, List, Tuple

def parse_and_map_features(math_features: str) -> Tuple[Dict[str, str], Dict[str, List[str]]]:
    """
    Parses a string of features (FEATURE:VALUE | FEATURE:VALUE) into two dictionaries:
    1. feature_to_value: FEATURE -> VALUE (1:1 mapping)
    2. value_to_features: VALUE -> [List of FEATURES] (1:Many mapping)

    Args:
        math_features: A string containing the '|' separated features.

    Returns:
        A tuple of two dictionaries: (feature_to_value, value_to_features)
    """
    feature_to_value: Dict[str, str] = {}
    # Use a list to store features because one value can have multiple feature names
    value_to_features: Dict[str, List[str]] = defaultdict(list)

    # The features are separated by ' | '
    feature_list = [f.strip() for f in math_features.split('|')]

    # Process each FEATURE:VALUE pair
    for pair in feature_list:
        if ':' not in pair:
            continue

        try:
            feature, value = pair.split(':', 1)
            feature = feature.strip()
            value = value.strip()

            # 1. Feature -> Value dictionary (direct 1:1)
            feature_to_value[feature] = value

            # 2. Value -> Feature list dictionary (1:Many)
            value_to_features[value].append(feature)

        except Exception:
            # Skip malformed pairs
            continue

    return dict(feature_to_value), dict(value_to_features)
