    if any(err_name in feature_name for err_name in
           ['SwapDividend', 'FlipChange', 'Whole_numbers_larger', 'Longer_is_bigger',
            'Ignores_zeroes', 'CorrectAnswer', 'div']):
        return 5

    # Priority 6: Operation/Transformation Tags
    if any(op_name in feature_name for op_name in
           ['SIM', 'UNSIM', 'RECIP', 'MIXED', 'MULT', 'DIV', 'ADD', 'DIFF', 'GCD', 'LCM',
            'F1divN1_SIM', 'F1divN3_SIM', 'TIMES_WHOLE']):
        return 6

    # Priority 7: General Fraction parts
    if any(f_name in feature_name for f_name in ['FRAC', 'F1_NUM', 'F1_DEN']):
        return 7

    # Priority 8: Student Answer
    if feature_name == 'SA':
        return 8

    # Priority 9: Meta counts
    if feature_name in ['NUM_COUNT', 'FRAC_COUNT']:
        return 9

    return 10
