def preprocess_arithmetic_expressions_pt2(
    text: str,
    value_to_features: Dict[str, List[str]],
    get_rank
) -> str:
    """
    Pre-process arithmetic expressions and substitute values within algebraic expressions
    for problem_type 2.
    """

    # STEP 1: Process algebraic expressions first (e.g., 8n+2)
    # Match patterns like: [NUMBER][letter][+|-][NUMBER]
    # (The simple [NUMBER][letter] is handled by this pattern where the last part is optional)
    # The pattern is: (coeff) (var) (optional: op) (optional: const)
    algebraic_pattern = r'(\d+)\s*([a-z])(?:\s*([+\-])\s*(\d+))?\b'

    # We will substitute the coefficient and constant directly
    def substitute_algebraic(match):
        coefficient_str = match.group(1)
        variable = match.group(2)
        operator = match.group(3)
        constant_str = match.group(4)

        # --- Substitute Coefficient (e.g., '8' in '8n') ---
        if coefficient_str in value_to_features:
            features = value_to_features[coefficient_str]
            coefficient_feature = min(features, key=get_rank)
        else:
            coefficient_feature = coefficient_str

        # --- Substitute Constant (e.g., '2' in '8n+2') ---
        if constant_str and constant_str in value_to_features:
            features = value_to_features[constant_str]
            constant_feature = min(features, key=get_rank)
        else:
            constant_feature = constant_str

        # Rebuild the algebraic expression with substituted features
        new_expr = f"{coefficient_feature}{variable}"
        if operator and constant_feature:
            new_expr += f"{operator}{constant_feature}"

        return new_expr

    # Apply the algebraic substitution
    text_processed = re.sub(algebraic_pattern, substitute_algebraic, text, flags=re.IGNORECASE)

    # STEP 2: Process arithmetic expressions (e.g., 6x5, 10 + 2)
    # Find patterns like: NUMBER [operator] NUMBER
    arithmetic_pattern = r'(\d+)\s*([x*×·+\-])\s*(\d+)'

    def replace_arithmetic(match):
        num1 = match.group(1)
        operator = match.group(2)
        num2 = match.group(3)

        full_match = match.group(0)

        # Check if either number should NOT be substituted
        if num1 not in value_to_features or num2 not in value_to_features:
            return full_match

        # Get best feature names for each number
        feature1 = min(value_to_features[num1], key=get_rank)
        feature2 = min(value_to_features[num2], key=get_rank)

        # Build replacement string with spaces for clarity
        return f"{feature1} {operator} {feature2}"

    # Apply the arithmetic substitution to the text already processed for algebraic expressions
    result = re.sub(arithmetic_pattern, replace_arithmetic, text_processed)

    # No Step 3 required (algebraic restoration) since we substituted in Step 1

    return result


