def debug_substitution(
    value_to_features: Dict[str, List[str]],
    student_explanation: str,
    problem_type: int
) -> None:
    """Show exactly what's happening with substitutions"""

    ranking_functions = {
        1: get_feature_priority_rank_problem_type1,
        2: get_feature_priority_rank_problem_type2
    }
    get_rank = ranking_functions.get(problem_type, get_feature_priority_rank_problem_type1)

    print("="*80)
    print(f"DEBUG: Problem Type {problem_type}")
    print("="*80)
    print(f"\nOriginal: {student_explanation}\n")

    # Show if arithmetic preprocessing will happen
    if problem_type == 2:
        preprocessed = preprocess_arithmetic_expressions_pt2(
            student_explanation,
            value_to_features,
            get_rank
        )
        if preprocessed != student_explanation:
            print(f"After arithmetic preprocessing: {preprocessed}\n")

    # Show priority rankings for each value
    print("Value → Feature Priorities:")
    for value_str in sorted(value_to_features.keys(), key=len, reverse=True):
        if len(value_str) < 1 or value_str.upper() in ['TRUE', 'FALSE', 'N/A']:
            continue

        features = value_to_features[value_str]
        ranked = [(f, get_rank(f)) for f in features]
        ranked.sort(key=lambda x: x[1])

        print(f"\n  '{value_str}':")
        for i, (fname, rank) in enumerate(ranked[:5]):  # Show top 5
            marker = "✓✓✓" if i == 0 else "   "
            print(f"    {marker} [{rank:2d}] {fname}")

    # Show result
    result = place_generic_features_in_text(value_to_features, student_explanation, problem_type)
    print(f"\n{'='*80}")
    print(f"Result: {result}")
    print("="*80)
