          # Calculate LCM of all denominators
          def lcm(a, b):
              return abs(a * b) // math.gcd(a, b)

          def lcm_multiple(nums):
              result = nums[0]
              for num in nums[1:]:
                  result = lcm(result, num)
              return result

          # Calculate GCD of all denominators
          def gcd_multiple(nums):
              result = nums[0]
              for num in nums[1:]:
                  result = math.gcd(result, num)
              return result

          overall_lcm = lcm_multiple(denominators)
