            # 1. LONGEST DECIMAL (Max Decimal Places)
            max_decimal_places = max(decimal_places_counts.values())
            longest_decimals = [n for n, count in decimal_places_counts.items() if count == max_decimal_places]

            longest_decimal_value = longest_decimals[0]
            longest_place_name = get_place_name(longest_decimal_value) # <--- NEW

            features.append(f"MAX_DECIMAL_PLACES_COUNT:{max_decimal_places}")
            features.append(f"LONGEST_DECIMAL_VALUE:{longest_decimal_value:.12g}")
